class MainActivity : AppCompatActivity() {

    // --- NEBULA PALETTE ---
    private val C_BG = 0xFF050505.toInt()
    private val C_CARD = 0xFF1E1E23.toInt()
    private val C_ACCENT_1 = 0xFF7F5AF0.toInt() // Purple
    private val C_ACCENT_2 = 0xFF2CB67D.toInt() // Green
    private val C_ACCENT_3 = 0xFF2CB1BC.toInt() // Cyan
    private val C_TEXT_MAIN = 0xFFFFFFFE.toInt()
    private val C_TEXT_SUB = 0xFF94A1B2.toInt()

    private lateinit var contentContainer: LinearLayout
    private val handler = Handler(Looper.getMainLooper())
    private val cpuRunnable = object : Runnable {
        override fun run() {
            updateCpuBars()
            handler.postDelayed(this, 200)
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // 1. Window Setup
        window.statusBarColor = C_BG
        window.navigationBarColor = C_BG
        supportActionBar?.hide()

        // 2. Main Frame (Layers: Content + Dock)
        val mainFrame = FrameLayout(this).apply {
            setBackgroundColor(C_BG)
        }

        // 3. Scrollable Content Area
        val scrollView = ScrollView(this).apply {
            layoutParams = FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.MATCH_PARENT).apply {
                bottomMargin = 200 // Space for Dock
            }
            isVerticalScrollBarEnabled = false
        }

        contentContainer = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(40, 60, 40, 60)
        }
        scrollView.addView(contentContainer)

        // 4. Floating Dock
        val dock = createDock()

        mainFrame.addView(scrollView)
        mainFrame.addView(dock)
        setContentView(mainFrame)

        // 5. Init Home
        loadHome()
    }

    // --- NAVIGATION ---
    private fun createDock(): View {
        val dock = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            gravity = Gravity.CENTER
            layoutParams = FrameLayout.LayoutParams(ViewGroup.LayoutParams.WRAP_CONTENT, 140).apply {
                gravity = Gravity.BOTTOM or Gravity.CENTER_HORIZONTAL
                bottomMargin = 50
            }
            setPadding(30, 20, 30, 20)
            background = GradientDrawable().apply {
                color = android.content.res.ColorStateList.valueOf(Color.parseColor("#CC141414"))
                cornerRadius = 100f
                setStroke(2, 0xFF333333.toInt())
            }
            elevation = 40f
        }

        val items = listOf("🏠", "📡", "🛠️", "🤖")
        val actions = listOf(::loadHome, ::loadNetwork, ::loadHardware, ::loadSystem)

        items.forEachIndexed { index, icon ->
            dock.addView(TextView(this).apply {
                text = icon
                textSize = 22f
                setPadding(40, 20, 40, 20)
                setOnClickListener {
                    contentContainer.removeAllViews()
                    actions[index].invoke()
                }
            })
        }
        return dock
    }

    // --- PAGES ---

    private fun loadHome() {
        addHeader("SYSTEM ACTIVE", Build.MODEL, "${Build.MANUFACTURER} • ${Build.ID}")

        // Battery Card (Wide)
        val batt = getBatteryInfo()
        val battCard = createCard()
        battCard.addView(createLabel("POWER CELL"))
        battCard.addView(createValueLarge(batt["pct"] ?: "0%"))
        battCard.addView(createValueSmall("${batt["status"]} • ${batt["temp"]} • ${batt["volt"]}"))
        battCard.addView(createProgressBar(batt["intLevel"] ?: 0, C_ACCENT_2))
        contentContainer.addView(battCard)

        // Grid: RAM & CPU
        val grid = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            weightSum = 2f
        }
        // RAM
        val ram = getRamInfo()
        val ramCard = createCard().apply {
            layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f).apply { marginEnd = 15 }
            gravity = Gravity.CENTER
        }
        ramCard.addView(createLabel("RAM USAGE"))
        ramCard.addView(DonutView(this, ram["pct"] ?: 0, C_ACCENT_1).apply {
            layoutParams = LinearLayout.LayoutParams(150, 150).apply { topMargin = 30; bottomMargin = 30 }
        })
        ramCard.addView(createValueSmall("${ram["used"]} / ${ram["total"]} GB"))

        // CPU
        val cpuCard = createCard().apply {
             layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f).apply { marginStart = 15 }
        }
        cpuCard.addView(createLabel("PROCESSOR"))
        cpuCard.addView(createCpuView())
        cpuCard.addView(createValueSmall("${Runtime.getRuntime().availableProcessors()} Cores Active"))
        cpuCard.addView(createValueSmall(Build.HARDWARE.uppercase()))

        grid.addView(ramCard)
        grid.addView(cpuCard)
        contentContainer.addView(grid)

        // Start Anim
        handler.removeCallbacks(cpuRunnable)
        handler.post(cpuRunnable)
    }

    private fun loadNetwork() {
        addHeader("LINK STATUS", "Connectivity", "Real-time Analysis")
        val net = getNetworkData()

        // Status Card
        val main = createCard()
        main.addView(createLabel("CONNECTION"))
        main.addView(createValueLarge(net["type"] ?: "No Link"))
        main.addView(createValueSmall(net["status"] ?: "Disconnected"))
        contentContainer.addView(main)

        // Details Grid
        val grid = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            weightSum = 2f
        }
        val c1 = createCard().apply { layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f).apply { marginEnd = 15 } }
        c1.addView(createLabel("DOWNLINK"))
        c1.addView(createValueMedium(net["down"] ?: "0"))

        val c2 = createCard().apply { layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f).apply { marginStart = 15 } }
        c2.addView(createLabel("UPLINK"))
        c2.addView(createValueMedium(net["up"] ?: "0"))

        grid.addView(c1)
        grid.addView(c2)
        contentContainer.addView(grid)

        // IP & Config
        val ip = createCard()
        ip.addView(createRow("LOCAL IP", net["ip"] ?: "0.0.0.0"))
        ip.addView(createRow("METERED", net["metered"] ?: "?"))
        contentContainer.addView(ip)
    }

    private fun loadHardware() {
        addHeader("HARDWARE", "Sensors & Display", "Physical Matrix")

        // Display
        val disp = getDisplayData()
        val dCard = createCard()
        dCard.addView(createLabel("DISPLAY MATRIX"))
        dCard.addView(createRow("RESOLUTION", disp["res"] ?: ""))
        dCard.addView(createRow("REFRESH", disp["hz"] ?: ""))
        dCard.addView(createRow("DENSITY", disp["dpi"] ?: ""))
        dCard.addView(createRow("HDR", disp["hdr"] ?: ""))
        contentContainer.addView(dCard)

        // Features
        val fCard = createCard()
        fCard.addView(createLabel("CAPABILITIES"))
        val flow = LinearLayout(this).apply { orientation = LinearLayout.VERTICAL }
        getFeatures().forEach { (k, v) ->
             if(v == "true") flow.addView(createPill(k, C_ACCENT_2))
        }
        fCard.addView(flow)
        contentContainer.addView(fCard)

        // Sensors
        val sCard = createCard()
        sCard.addView(createLabel("SENSOR ARRAY"))
        val sList = getSensors()
        sCard.addView(createValueMedium("${sList.size} Detected"))
        val sFlow = LinearLayout(this).apply { 
            orientation = LinearLayout.VERTICAL 
            topMargin = 20
        }
        sList.take(10).forEach { s -> sFlow.addView(createPill(s.name, C_ACCENT_3)) }
        sCard.addView(sFlow)
        contentContainer.addView(sCard)
    }

    private fun loadSystem() {
        addHeader("INTERNAL", "Operating System", "Android ${Build.VERSION.RELEASE}")

        val os = createCard()
        os.addView(createLabel("BUILD CONFIG"))
        os.addView(createRow("SDK LEVEL", Build.VERSION.SDK_INT.toString()))
        os.addView(createRow("SECURITY", if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) Build.VERSION.SECURITY_PATCH else "Unknown"))
        os.addView(createRow("BOOTLOADER", Build.BOOTLOADER))
        os.addView(createRow("ABIs", Build.SUPPORTED_ABIS.joinToString(", ")))
        contentContainer.addView(os)

        val kern = createCard()
        kern.addView(createLabel("KERNEL & HOST"))
        kern.addView(createValueSmall(System.getProperty("os.version") ?: "Unknown"))
        kern.addView(createValueSmall("${Build.USER}@${Build.HOST}"))
        contentContainer.addView(kern)

        // Storage
        val stor = getStorageData()
        val stCard = createCard()
        stCard.addView(createLabel("INTERNAL STORAGE"))
