        stCard.addView(createValueSmall("of ${stor["total"]} GB Total"))
        stCard.addView(createProgressBar(stor["pct"] ?: 0, C_ACCENT_1))
        contentContainer.addView(stCard)
    }

    // --- UI HELPERS ---

    private fun addHeader(pill: String, title: String, sub: String) {
        contentContainer.addView(TextView(this).apply {
            text = pill
            textSize = 10f
            setTextColor(C_ACCENT_2)
            background = GradientDrawable().apply {
                color = android.content.res.ColorStateList.valueOf(0xFF1A1A1A.toInt())
                cornerRadius = 10f
                setStroke(1, C_ACCENT_2)
            }
            setPadding(16, 4, 16, 4)
            layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.WRAP_CONTENT, ViewGroup.LayoutParams.WRAP_CONTENT)
        })
