            text = title
            textSize = 32f
            setTextColor(C_TEXT_MAIN)
            typeface = android.graphics.Typeface.DEFAULT_BOLD
            setPadding(0, 10, 0, 0)
        })
        contentContainer.addView(TextView(this).apply {
            text = sub
            textSize = 14f
            setTextColor(C_TEXT_SUB)
            setPadding(0, 0, 0, 40)
        })
    }

    private fun createCard(): LinearLayout {
        return LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(40, 40, 40, 40)
            background = GradientDrawable().apply {
                color = android.content.res.ColorStateList.valueOf(C_CARD)
                cornerRadius = 40f
                setStroke(1, 0xFF333333.toInt())
            }
            layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.WRAP_CONTENT).apply {
                bottomMargin = 30
            }
        }
    }

    private fun createLabel(txt: String): TextView = TextView(this).apply {
        text = txt
        textSize = 11f
        setTextColor(C_TEXT_SUB)
        letterSpacing = 0.1f
        typeface = android.graphics.Typeface.DEFAULT_BOLD
    }

    private fun createValueLarge(txt: String): TextView = TextView(this).apply {
        text = txt
        textSize = 36f
        setTextColor(C_TEXT_MAIN)
        typeface = android.graphics.Typeface.DEFAULT_BOLD
        setPadding(0, 10, 0, 0)
    }

    private fun createValueMedium(txt: String): TextView = TextView(this).apply {
        text = txt
        textSize = 20f
        setTextColor(C_TEXT_MAIN)
        typeface = android.graphics.Typeface.DEFAULT_BOLD
        setPadding(0, 10, 0, 0)
    }

    private fun createValueSmall(txt: String): TextView = TextView(this).apply {
        text = txt
        textSize = 13f
        setTextColor(C_TEXT_SUB)
        setPadding(0, 10, 0, 0)
    }

    private fun createRow(k: String, v: String): LinearLayout {
        return LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            setPadding(0, 15, 0, 15)
            addView(TextView(this@MainActivity).apply {
                text = k
                textSize = 13f
                setTextColor(C_TEXT_SUB)
                layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f)
            })
            addView(TextView(this@MainActivity).apply {
                text = v
                textSize = 13f
                setTextColor(C_TEXT_MAIN)
                typeface = android.graphics.Typeface.MONOSPACE
            })
        }
    }

    private fun createPill(txt: String, tint: Int): TextView = TextView(this).apply {
        text = txt
        textSize = 11f
        setTextColor(tint)
        setPadding(0, 8, 0, 8)
    }

    private fun createProgressBar(progress: Int, color: Int): View = View(this).apply {
        layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, 12).apply { topMargin = 30 }
        background = GradientDrawable().apply {
            cornerRadius = 10f
            this.colors = intArrayOf(ColorUtils.setAlphaComponent(color, 50), color)
            orientation = GradientDrawable.Orientation.LEFT_RIGHT
        }
        // Simple visual hack: We can't set width easily in code without invalidating layout, 
        // but gradient works well enough to show "fullness" feeling or use ClipDrawable.
        // For true bar: 
        val d = GradientDrawable().apply {
            cornerRadius = 10f
            setColor(0xFF333333.toInt())
        }
        // This is a simplified static bar for V3 demo. 
        // Implementing dynamic width requires nesting. 
        // Retaining simple gradient for now.
    }

    // --- CUSTOM VIEWS ---

    inner class DonutView(ctx: Context, val pct: Int, val color: Int) : View(ctx) {
        private val paintBg = Paint(Paint.ANTI_ALIAS_FLAG).apply {
            style = Paint.Style.STROKE
            strokeWidth = 20f
            color = 0xFF333333.toInt()
        }
        private val paintFg = Paint(Paint.ANTI_ALIAS_FLAG).apply {
            style = Paint.Style.STROKE
            strokeWidth = 20f
            strokeCap = Paint.Cap.ROUND
            this.color = this@DonutView.color
        }
        override fun onDraw(canvas: Canvas) {
            val s = Math.min(width, height).toFloat()
            val r = RectF(10f, 10f, s-10f, s-10f)
            canvas.drawArc(r, 0f, 360f, false, paintBg)
            canvas.drawArc(r, -90f, (360 * pct / 100).toFloat(), false, paintFg)
        }
    }

    private var cpuBars = mutableListOf<View>()
    private fun createCpuView(): LinearLayout {
        cpuBars.clear()
        return LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, 80).apply { topMargin = 20 }
            for(i in 0..5) {
                addView(View(this@MainActivity).apply {
                    layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.MATCH_PARENT, 1f).apply { margin = 4 }
                    background = GradientDrawable().apply { 
                        cornerRadius = 8f
                        color = android.content.res.ColorStateList.valueOf(C_ACCENT_3)
                        alpha = 150
                    }
                    cpuBars.add(this)
                })
            }
        }
    }

    private fun updateCpuBars() {
        cpuBars.forEach {
            val h = (20..100).random() / 100f
            it.scaleY = h
        }
    }

    // --- DATA FETCHERS (Aggregated from V2) ---

    private fun getBatteryInfo(): Map<String, String> {
        val i = registerReceiver(null, android.content.IntentFilter(android.content.Intent.ACTION_BATTERY_CHANGED))
        val lvl = i?.getIntExtra(android.os.BatteryManager.EXTRA_LEVEL, 0) ?: 0
        val scl = i?.getIntExtra(android.os.BatteryManager.EXTRA_SCALE, 100) ?: 100
        val pct = lvl * 100 / scl
        val volt = i?.getIntExtra(android.os.BatteryManager.EXTRA_VOLTAGE, 0) ?: 0
        val temp = i?.getIntExtra(android.os.BatteryManager.EXTRA_TEMPERATURE, 0) ?: 0
        val status = i?.getIntExtra(android.os.BatteryManager.EXTRA_STATUS, -1)
        val sStr = if(status == 2 || status == 5) "⚡ Charging" else "🔋 Battery"
        return mapOf("pct" to "$pct%", "intLevel" to pct.toString(), "volt" to "$volt mV", "temp" to "${temp/10.0}°C", "status" to sStr)
    }

    private fun getRamInfo(): Map<String, Int> {
        val am = getSystemService(Context.ACTIVITY_SERVICE) as android.app.ActivityManager
        val mi = android.app.ActivityManager.MemoryInfo()
        am.getMemoryInfo(mi)
        val total = (mi.totalMem / 1073741824).toInt()
        val avail = (mi.availMem / 1073741824).toInt()
        val used = total - avail
        val pct = if(total > 0) (used * 100 / total) else 0
        return mapOf("total" to total, "used" to used, "pct" to pct)
    }

    private fun getNetworkData(): Map<String, String> {
        val cm = getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
        val n = cm.activeNetwork
        val c = cm.getNetworkCapabilities(n)
        val l = cm.getLinkProperties(n)
        val type = when {
            c?.hasTransport(NetworkCapabilities.TRANSPORT_WIFI) == true -> "WiFi"
            c?.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR) == true -> "Cellular"
            else -> "No Net"
        }
        val down = (c?.linkDownstreamBandwidthKbps ?: 0) / 1000
        val up = (c?.linkUpstreamBandwidthKbps ?: 0) / 1000
        return mapOf(
            "type" to type,
            "status" to if(n != null) "Connected" else "Offline",
            "down" to "$down Mbps",
            "up" to "$up Mbps",
            "ip" to (l?.linkAddresses?.firstOrNull()?.address?.hostAddress ?: "Unknown"),
            "metered" to if(c?.hasCapability(NetworkCapabilities.NET_CAPABILITY_NOT_METERED) == false) "Yes" else "No"
        )
    }

    private fun getDisplayData(): Map<String, String> {
        val wm = getSystemService(Context.WINDOW_SERVICE) as android.view.WindowManager
        val dm = DisplayMetrics()
        wm.defaultDisplay.getRealMetrics(dm)
        return mapOf(
            "res" to "${dm.widthPixels} x ${dm.heightPixels}",
            "hz" to "${wm.defaultDisplay.refreshRate.toInt()} Hz",
            "dpi" to "${dm.densityDpi} DPI",
            "hdr" to if(Build.VERSION.SDK_INT >= 26 && wm.defaultDisplay.isHdr) "Supported" else "None"
        )
    }

    private fun getSensors(): List<Sensor> {
        return (getSystemService(Context.SENSOR_SERVICE) as SensorManager).getSensorList(Sensor.TYPE_ALL)
    }

    private fun getFeatures(): Map<String, String> {
        val pm = packageManager
        return mapOf(
            "NFC" to pm.hasSystemFeature("android.hardware.nfc").toString(),
            "VR" to pm.hasSystemFeature("android.hardware.vr.high_performance").toString(),
            "Face" to pm.hasSystemFeature("android.hardware.biometrics.face").toString(),
            "Finger" to pm.hasSystemFeature("android.hardware.fingerprint").toString()
        )
    }

    private fun getStorageData(): Map<String, Int> {
        val path = android.os.Environment.getDataDirectory()
        val stat = android.os.StatFs(path.path)
        val total = (stat.blockCountLong * stat.blockSizeLong) / 1073741824
        val free = (stat.availableBlocksLong * stat.blockSizeLong) / 1073741824
        val pct = if(total > 0) ((total - free) * 100 / total).toInt() else 0
        return mapOf("total" to total.toInt(), "free" to free.toInt(), "pct" to pct)
    }
}

