export function renderDeckScreen() {
    const { decks, folders } = getState();
    renderSidebar();

    const state = getCurrentViewState();
    const icon = document.querySelector('#deck-display-mode-toggle-btn i');
    if(icon) icon.className = state.viewMode === 'list' ? 'ph ph-squares-four' : 'ph ph-list-bullets';
    document.getElementById('deck-display-mode-toggle-btn').title = state.viewMode === 'list' ? 'Switch to Grid View' : 'Switch to List View';

    Object.values(DOM.deckViews).forEach(view => view.classList.remove('active'));

    const viewType = currentDeckView.startsWith('folder_') ? 'single_folder' : currentDeckView;

    switch (viewType) {
        case 'all':
            DOM.deckViews.all.classList.add('active');
            DOM.decksScreenTitle.textContent = "All Decks";
            const sortedDecks = getSortedAndFilteredItems(decks, state);
            const gridContainer = document.getElementById('all-decks-grid-container');
            const listContainer = document.getElementById('all-decks-list-container');
            const noResultsEl = document.getElementById('no-decks-filter-results');

            if (state.viewMode === 'list') {
                gridContainer.parentElement.classList.remove('active');
                listContainer.parentElement.classList.add('active');
                actions.ui.renderDecksList(sortedDecks, listContainer);
            } else {
                listContainer.parentElement.classList.remove('active');
                gridContainer.parentElement.classList.add('active');
                actions.ui.renderDecks(sortedDecks, gridContainer);
            }

            if (sortedDecks.length === 0) {
                noResultsEl.style.display = 'block';
                gridContainer.parentElement.classList.remove('active');
                listContainer.parentElement.classList.remove('active');
