operations.content:
import * as api from './api.js';

let getState = () => ({});
let actions = {};

export function initEnrichment(config) {
    getState = config.getState;
    actions = config.actions;
    console.log("Enrichment module initialized.");
}

async function filterSafeImages(images) {
    if (!images || images.length === 0) return [];
    const forbiddenKeywords = ['bikini', 'lingerie', 'underwear', 'nude', 'naked', 'erotic', 'boudoir', 'sensual', 'provocative', 'scantily clad', 'cleavage', 'bra', 'panty'];
    const initiallyFiltered = images.filter(img => !forbiddenKeywords.some(k => (img.description || '').toLowerCase().includes(k)));
    if (initiallyFiltered.length === 0) return [];

    const { supabaseUrl, supabaseAnonKey } = getState();
    if (!supabaseUrl || !supabaseAnonKey) return initiallyFiltered;

    try {
        const descriptions = initiallyFiltered.map((img, i) => `Image ${i}: "${img.description}"`).join('\n');
        const prompt = `You are an AI content moderator. Decide if each image description is "SAFE" or "UNSAFE" (NSFW, revealing, swimwear/underwear). Respond ONLY with JSON: { "results": [{ "image_index": 0, "status": "SAFE" }] }.\n\n${descriptions}`;
        const result = await api.getJsonFromAi([{ role: 'user', content: prompt }]);
        if (!result || !Array.isArray(result.results)) return initiallyFiltered;
        const unsafeIndices = new Set(result.results.filter(r => r.status === 'UNSAFE').map(r => r.image_index));
        return initiallyFiltered.filter((_, i) => !unsafeIndices.has(i));
    } catch (e) {
        console.error("[AI Safety] Error:", e);
        return initiallyFiltered;
    }
}

export async function getBestImageForQuery(query, context) {
    const { supabaseUrl, supabaseAnonKey, apiSettings } = getState();
    if (!supabaseUrl || !supabaseAnonKey || (apiSettings && !apiSettings.images)) return null;

    try {
        const res = await api.searchUnsplash(query);
        if (!res.images || res.images.length === 0) return null;
        const safeImages = await filterSafeImages(res.images);
        if (safeImages.length === 0) return null;

        const descriptions = safeImages.map((img, i) => `Image ${i}: "${img.description}" (URL: ${img.url})`).join('\n');
        const prompt = `Find the best image for context: "${context}". Choose based on concept. Respond ONLY with the URL. If none fit, respond "REJECT".\n\n${descriptions}`;
        const url = await api.getGroqCompletion([{ role: 'user', content: prompt }]);
        return (url && url.trim() !== 'REJECT' && url.startsWith('http')) ? url.trim() : null;
    } catch (error) {
        if (error.message.includes("API rate limit")) throw error;
        console.error("[Enrichment] Image search error:", error);
        return undefined;
    }
}

export async function getBestImageUsingAI(wordObject, deckObject) {
    const populated = await populateWordData(wordObject, deckObject);
    const def = populated.definitions.flashcard || 'No definition.';
    const prompt = `Generate a concise (2-4 words) image search term for: "${populated.text}" (${def}). Respond ONLY with the term.`;
    const term = await api.getGroqCompletion([{ role: 'user', content: prompt }]);
    if (!term) return null;
    const url = await getBestImageForQuery(term.trim(), def);
    return url ? { imageUrl: url, query: term.trim() } : null;
}

export async function populateWordData(wordObject, deck, options = {}) {
    const { automationSettings, apiSettings } = getState();
    const deckType = deck.type || 'Vocabulary';
    let needsSave = false;

    const isAutoDefEnabled = automationSettings.enableAutoDefinitions && 
                             automationSettings.autoDefinitionsDeckTypes[deckType] !== false &&
                             !automationSettings.autoDefinitionsDeckTypes.blacklist.includes(deck.id);

    if (isAutoDefEnabled && navigator.onLine) {
        const hasDef = wordObject.definitions.flashcard && wordObject.definitions.detailed;
        if (!hasDef && deckType !== 'General Study') {
            try {
                if ((deckType === 'Vocabulary' || deckType === 'Expressions') && apiSettings.publicDictionary) {
                    const res = await fetch(`https://api.dictionaryapi.dev/api/v2/entries/en/${encodeURIComponent(wordObject.text)}`);
                    if (res.ok) {
                        const data = await res.json();
                        if (data[0]) {
                            wordObject.definitions.detailed = { word: data[0].word, phonetic: data[0].phonetic, meanings: data[0].meanings };
                            if (!wordObject.definitions.flashcard) wordObject.definitions.flashcard = data[0].meanings[0]?.definitions[0]?.definition;
                            needsSave = true;
                        }
                    }
                }
                if (!wordObject.definitions.flashcard || deckType === 'Subtitle') {
                    const aiDef = await api.getExplanationFromAi(wordObject, deck);
                    wordObject.definitions.flashcard = aiDef.flashcard;
                    wordObject.definitions.detailed = aiDef.detailed;
                    if (!wordObject.example && typeof aiDef.detailed === 'string') {
                        const m = aiDef.detailed.match(/(?:Example:|e\.g\.)\s*"?(.+?)"?$/im);
                        if (m) wordObject.example = m[1].trim();
                    }
                    needsSave = true;
                }
            } catch (e) { console.error("[Enrichment] Def fetch failed:", e); }
        }

        if (!wordObject.definitions.gemini && deckType !== 'General Study') {
            try {
                const amh = await api.getAmharicDefinitionFromGemini(wordObject.text);
                wordObject.definitions.gemini = amh;
                needsSave = true;
            } catch (e) {}
        }

        if (!wordObject.definitions.merriamWebster && deckType === 'Vocabulary' && options.fetchMw !== false) {
            try {
                const [dict, thes] = await Promise.all([
                    api.callSupabaseFunction('merriam-webster-lookup', { type: 'dictionary', word: wordObject.text.toLowerCase() }),
                    api.callSupabaseFunction('merriam-webster-lookup', { type: 'thesaurus', word: wordObject.text.toLowerCase() })
                ]);
                wordObject.definitions.merriamWebster = { dictionary: dict, thesaurus: thes };
                needsSave = true;
            } catch (e) {}
        }
    }

    const isImageAuto = automationSettings.enableImageAutomation && 
                        automationSettings.imageAutomationDeckTypes[deckType] !== false &&
                        !automationSettings.imageAutomationDeckTypes.blacklist.includes(deck.id);

    if (isImageAuto && wordObject.isImageProvisional && !wordObject.imageUrl && navigator.onLine) {
        try {
            const res = await api.searchUnsplash(wordObject.text);
            if (res.images?.[0]) {
                wordObject.imageUrl = res.images[0].url;
                wordObject.image_query = wordObject.text;
                needsSave = true;
            }
        } catch (e) {}
    }

    if (needsSave) actions.saveDecks();
    return wordObject;
}

export async function refineWordImagesInBackground() {
    const { automationSettings, decks } = getState();
    if (!automationSettings.enableImageAutomation || !navigator.onLine) return;

    const wordsToRefine = [];
    decks.forEach(deck => {
        if (deck.isSpecial || automationSettings.imageAutomationDeckTypes.blacklist.includes(deck.id)) return;
        if (automationSettings.imageAutomationDeckTypes[deck.type || 'Vocabulary'] === false) return;
        deck.words.forEach(w => { if (w.isImageProvisional === true) wordsToRefine.push({ ...w, deckId: deck.id }); });
    });

    if (wordsToRefine.length === 0) return;

    let refinedCount = 0;
    for (const item of wordsToRefine) {
        if (refinedCount >= 25) break;
        const deck = decks.find(d => d.id === item.deckId);
        const word = deck?.words.find(w => w.text === item.text);
        if (!word) continue;

        try {
            const res = await getBestImageUsingAI(word, deck);
            if (res && res.imageUrl) {
                word.imageUrl = res.imageUrl;
                word.image_query = res.query;
            }
            word.isImageProvisional = false;
            actions.saveDecks();
            refinedCount++;
            if (refinedCount < 25) await new Promise(r => setTimeout(r, 10000));
        } catch (e) { 
            if(e.message.includes('rate limit')) break; 
        }
    }
}

let api, ui, getState, actions, DOM;
let publicDecks = [];
let currentPublicDeck = null;
let sortFilter = { sort: 'date_desc', filter: { type: 'type_all', size: null } };

export function initExplore(config) {
    api = config.api;
    ui = config.ui;
    getState = config.getState;
    actions = config.actions;
    DOM = config.elements;
    setupEventListeners();
}

export async function showExploreDecksScreen() {
    ui.showModal(DOM.screens.exploreList);
    const grid = document.getElementById('published-deck-grid');
    grid.innerHTML = '<p style="text-align: center; color: var(--text-secondary);">Loading library...</p>';
    const { supabaseUrl, supabaseAnonKey } = getState();

    if (!supabaseUrl || !supabaseAnonKey || !navigator.onLine) {
        grid.innerHTML = `<div class="no-results-message"><p>Check connection & settings.</p></div>`;
        return;
    }

    try {
        const res = await fetch(`${supabaseUrl}/rest/v1/published_decks?select=*&order=downloads.desc,created_at.desc`, {
            headers: { 'apikey': supabaseAnonKey, 'Authorization': `Bearer ${supabaseAnonKey}` }
        });
        if (!res.ok) throw new Error(res.statusText);
        publicDecks = await res.json();
        applySortAndFilter();
    } catch (e) {
        grid.innerHTML = `<div class="no-results-message"><p>Error loading library: ${e.message}</p></div>`;
    }
}

function applySortAndFilter() {
    let items = [...publicDecks];
    const { sort, filter } = sortFilter;

    if (filter.type !== 'type_all') {
        if (filter.type === 'source_ai') items = items.filter(d => d.is_ai_generated);
        else if (filter.type === 'source_user') items = items.filter(d => !d.is_ai_generated);
        else {
            const map = { type_vocab: 'Vocabulary', type_expr: 'Expressions', type_sub: 'Subtitle' };
            items = items.filter(d => d.type === map[filter.type]);
        }
    }
    if (filter.size) {
        const { op, val1, val2 } = filter.size;
        items = items.filter(d => {
            const c = d.word_count;
            return op === 'gte' ? c >= val1 : op === 'lte' ? c <= val1 : op === 'eq' ? c === val1 : c >= val1 && c <= val2;
        });
    }
    items.sort((a, b) => {
        if (sort === 'date_asc') return new Date(a.created_at) - new Date(b.created_at);
        if (sort === 'name_asc') return a.title.localeCompare(b.title);
        if (sort === 'name_desc') return b.title.localeCompare(a.title);
        return new Date(b.created_at) - new Date(a.created_at);
    });
    renderPublishedDecks(items);
}

function renderPublishedDecks(items) {
    const grid = document.getElementById('published-deck-grid');
    if (!items.length) { grid.innerHTML = '<p class="no-results-message">No decks found.</p>'; return; }
    grid.innerHTML = items.map(d => `
        <div class="published-deck-card" data-deck-id="${d.id}">
            <div class="published-deck-image" style="background-image: url('${d.image_url}')"></div>
            <div class="published-deck-content">
                <h3 class="published-deck-title">${d.title}</h3>
                <p class="published-deck-desc">${d.description}</p>
                <div class="published-deck-meta">
                    <div class="meta-item"><span>${d.word_count} words</span></div>
                    <div class="meta-item"><span>${d.downloads || 0} DLs</span></div>
                </div>
            </div>
        </div>`).join('');
}

export async function handleUploadDeck(deckId) {
    const { decks, supabaseUrl, supabaseAnonKey } = getState();
    const deck = decks.find(d => d.id === deckId);
    if (!deck || !supabaseUrl) return;

    const confirm = await actions.showConfirmation({ title: `Upload "${deck.title}"?`, message: "Share with public library?", confirmText: "Upload", iconClass: "ph-fill ph-upload-simple" });
    if (!confirm) return;

    ui.showToast("Uploading...");
    try {
        const payload = {
            title: deck.title, description: deck.description, type: deck.type,
            image_url: deck.imageUrl, image_query: deck.image_query, word_count: deck.words.length,
            words: deck.words.map(w => ({
                text: w.text, definitions: w.definitions, imageUrl: w.isImageProvisional ? null : w.imageUrl,
                example: w.example, note: w.note, tags: w.tags
            }))
        };
        const res = await fetch(`${supabaseUrl}/rest/v1/published_decks`, {
            method: 'POST', headers: { 'apikey': supabaseAnonKey, 'Authorization': `Bearer ${supabaseAnonKey}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
            body: JSON.stringify(payload)
        });
        if (!res.ok) throw new Error((await res.json()).message);
        ui.showToast("Upload successful!");
    } catch (e) { ui.showToast(`Upload failed: ${e.message}`, true); }
}

function setupEventListeners() {
    const popover = document.getElementById('explore-sort-popover');
    const toggle = document.getElementById('explore-sort-toggle-btn');

    toggle.addEventListener('click', (e) => { e.stopPropagation(); popover.classList.toggle('visible'); toggle.classList.toggle('active'); });
    document.getElementById('explore-clear-filters-btn').addEventListener('click', () => { sortFilter = { sort: 'date_desc', filter: { type: 'type_all', size: null } }; applySortAndFilter(); popover.classList.remove('visible'); });

    popover.addEventListener('click', e => {
        const item = e.target.closest('.sort-item');
        if (item && item.dataset.sort) {
            const val = item.dataset.sort;
            if (val.startsWith('type_') || val.startsWith('source_')) sortFilter.filter.type = val;
            else if (val === 'size_all') sortFilter.filter.size = null;
            else sortFilter.sort = val;
            applySortAndFilter();
            popover.classList.remove('visible');
        }
    });

    document.getElementById('published-deck-grid').addEventListener('click', e => {
        const card = e.target.closest('.published-deck-card');
        if (card) {
            currentPublicDeck = publicDecks.find(d => d.id === card.dataset.deckId);
            if (currentPublicDeck) {
                ui.showModal(DOM.screens.exploreDetail);
                document.getElementById('deck-detail-title-explore').textContent = currentPublicDeck.title;
                document.getElementById('word-list-container').innerHTML = currentPublicDeck.words.map(w => `<div class="word-item-card"><div class="word-item-content"><h4>${w.text}</h4><p>${w.definitions.flashcard}</p></div></div>`).join('');
            }
        }
    });

    document.getElementById('import-public-deck-btn').addEventListener('click', () => {
        if (!currentPublicDeck) return;
        const { decks } = getState();
        if (decks.some(d => d.title.toLowerCase() === currentPublicDeck.title.toLowerCase())) {
            document.getElementById('conflict-summary').textContent = `Deck "${currentPublicDeck.title}" exists.`;
            ui.showModal(DOM.screens.importConflict);
        } else {
            importDeck(currentPublicDeck.title);
        }
    });

    // Conflict Modal Listeners
    document.getElementById('conflict-action-merge').addEventListener('click', () => {
        const { decks } = getState();
        const target = decks.find(d => d.title.toLowerCase() === currentPublicDeck.title.toLowerCase());
        const existing = new Set(target.words.map(w => w.text.toLowerCase()));
        let count = 0;
        currentPublicDeck.words.forEach(w => {
            if (!existing.has(w.text.toLowerCase())) {
