async function handleSearch() {
    const query = document.getElementById('image-search-input').value.trim();
    if (!query) return;
    const grid = document.getElementById('image-search-results-grid');
    grid.innerHTML = '<div class="loading"></div>';

    const useGoogle = document.getElementById('image-source-toggle-checkbox').checked;
    const res = useGoogle ? await api.searchGoogleImages(query) : await api.searchUnsplash(query, 30);

    if (res.error || !res.images?.length) {
        grid.innerHTML = '<p class="no-results-message">No results.</p>';
        return;
    }
    searchState.results = res.images;
    searchState.page = 1;
    renderPage(!useGoogle);
}

function renderPage(showPagination) {
    const grid = document.getElementById('image-search-results-grid');
    const perPage = 10;
    const start = (searchState.page - 1) * perPage;
    const display = showPagination ? searchState.results.slice(start, start + perPage) : searchState.results;

    grid.innerHTML = display.map(img => `<div class="image-result-card" data-url="${img.url}" style="background-image: url('${img.url}')"></div>`).join('');

    const pag = document.getElementById('image-search-pagination');
    if (showPagination && searchState.results.length > perPage) {
        pag.classList.add('visible');
        document.getElementById('image-search-page-indicator').textContent = `${searchState.page} / ${Math.ceil(searchState.results.length/perPage)}`;
    } else {
        pag.classList.remove('visible');
    }
}

