// /utils.js
// Generic utility functions used across multiple modules.

/**
 * Formats a date string into a relative time phrase (e.g., "5 min ago").
 * @param {string} dateString - The ISO date string.
 * @returns {string}
 */
export function formatRelativeTime(dateString) {
    if (!dateString) return "never";
    const date = new Date(dateString);
    const now = new Date();
    const seconds = Math.round((now - date) / 1000);
    const minutes = Math.round(seconds / 60);
    const hours = Math.round(minutes / 60);
    const days = Math.round(hours / 24);
    const months = Math.round(days / 30.44); // Average month length
    const years = Math.round(days / 365);

    if (seconds < 60) return "just now";
    if (minutes < 60) return `${minutes} min ago`;
    if (hours < 24) return `${hours} hr ago`;
    if (days < 30) return `${days} day${days > 1 ? 's' : ''} ago`;
    if (months < 12) return `${months} mo ago`;
    return `${years} yr ago`;
}

/**
 * Truncates a string in the middle, adding an ellipsis.
 * @param {string} text - The text to truncate.
 * @param {number} maxLength - The maximum desired length.
 * @returns {string}
 */
export function truncateInMiddle(text, maxLength) {
    if (!text || text.length <= maxLength) {
        return text;
    }
    const ellipsis = '...';
    const charsToShow = maxLength - ellipsis.length;
    const frontChars = Math.ceil(charsToShow / 2);
    const backChars = Math.floor(charsToShow / 2);

    return text.substring(0, frontChars) + ellipsis + text.substring(text.length - backChars);
}

/**
 * Converts an SRT time string (e.g., "00:01:23,456") to seconds.
 * @param {string} timeStr - The SRT time string.
 * @returns {number}
 */
export function srtTimeToSeconds(timeStr) {
    if (!timeStr) return 0;
    const parts = timeStr.split(/[:,]/);
    const hours = parseInt(parts[0], 10) || 0;
    const minutes = parseInt(parts[1], 10) || 0;
    const seconds = parseInt(parts[2], 10) || 0;
    const milliseconds = parseInt(parts[3], 10) || 0;
    return (hours * 3600) + (minutes * 60) + seconds + (milliseconds / 1000);
}

/**
 * Converts seconds to an SRT time string.
 * @param {number} totalSeconds - The total seconds.
 * @returns {string|null}
 */
export function secondsToSrtTime(totalSeconds) {
    if (typeof totalSeconds !== 'number' || isNaN(totalSeconds)) return null;
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = Math.floor(totalSeconds % 60);
    const milliseconds = Math.round((totalSeconds - Math.floor(totalSeconds)) * 1000);

    return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')},${String(milliseconds).padStart(3, '0')}`;
}

/**
 * Creates a debounced function that delays invoking the func until after wait milliseconds have passed.
 * @param {Function} func - The function to debounce.
 * @param {number} wait - The number of milliseconds to delay.
 * @returns {Function}
 */
export function debounce(func, wait) {
    let timeout;
    return function executedFunction(...args) {
        const later = () => {
            clearTimeout(timeout);
            func(...args);
        };
        clearTimeout(timeout);
        timeout = setTimeout(later, wait);
    };
}

/**
 * Speaks the given text using the Web Speech API.
 * @param {string} text - The text to speak.
 */
export function speakText(text) {
    if ('speechSynthesis' in window) {
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'en-US';
        window.speechSynthesis.speak(utterance);
    } else {
        console.warn("SpeechSynthesis API not supported in this browser.");
    }
}

// /state.js
// Centralized state management for the entire application.

import { createNewSrsWord } from './srs.js';

// --- State Variables ---
let state = {
    decks: [],
    folders: [],
    proficiencyLog: [],
    automationSettings: {},
    apiSettings: {},
    studySettings: {},
    defaultDeckViewMode: 'flashcard',
    viewStates: {},
    supabaseUrl: '',
    supabaseAnonKey: '',
    isErudaActive: false,
    publicDecks: [],
    currentPublicDeck: null,
};

// --- Getters ---
export const getDecks = () => state.decks;
export const getFolders = () => state.folders;
export const getProficiencyLog = () => state.proficiencyLog;
export const getAutomationSettings = () => state.automationSettings;
export const getApiSettings = () => state.apiSettings;
export const getStudySettings = () => state.studySettings;
export const getDefaultDeckViewMode = () => state.defaultDeckViewMode;
export const getViewStates = () => state.viewStates;
export const getSupabaseUrl = () => state.supabaseUrl;
export const getSupabaseAnonKey = () => state.supabaseAnonKey;
export const getPublicDecks = () => state.publicDecks;
export const getCurrentPublicDeck = () => state.currentPublicDeck;

// --- Setters & Mutators ---
export const setDecks = (newDecks) => { state.decks = newDecks; saveDecksToStorage(); };
export const setFolders = (newFolders) => { state.folders = newFolders; saveFoldersToStorage(); };
export const setAutomationSettings = (settings) => { state.automationSettings = settings; saveAutomationSettings(); };
export const setApiSettings = (settings) => { state.apiSettings = settings; saveApiSettings(); };
export const setStudySettings = (settings) => { state.studySettings = settings; saveStudySettings(); };
export const setViewStates = (viewStates) => { state.viewStates = viewStates; saveViewStates(); };
export const setPublicDecks = (decks) => { state.publicDecks = decks; };
export const setCurrentPublicDeck = (deck) => { state.currentPublicDeck = deck; };
export const addDeck = (deck) => { state.decks.push(deck); saveDecksToStorage(); };
export const updateDeck = (updatedDeck) => {
    const index = state.decks.findIndex(d => d.id === updatedDeck.id);
    if (index > -1) {
        state.decks[index] = { ...state.decks[index], ...updatedDeck };
        saveDecksToStorage();
    }
};
export const deleteDeck = (deckId) => {
    state.decks = state.decks.filter(d => d.id !== deckId);
    saveDecksToStorage();
};
export const addWordToDeck = (deckId, newWord) => {
    const deck = state.decks.find(d => d.id === deckId);
    if (deck) {
        deck.words.push(newWord);
        saveDecksToStorage();
    }
};

// --- Initialization & Persistence ---

export function loadAllState() {
    loadDecksFromStorage();
    loadFoldersFromStorage();
    loadProficiencyLog();
    loadAutomationSettings();
    loadApiSettings();
    loadStudySettings();
    loadViewStates();
    loadApiKeysFromStorage();
    state.isErudaActive = localStorage.getItem('wordwiseErudaActive') === 'true';
    state.defaultDeckViewMode = localStorage.getItem('wordwiseDefaultDeckView') || 'flashcard';

    // Migration logic
    if (!localStorage.getItem('wordwiseSrsMigrated')) {
        migrateSrsData();
        localStorage.setItem('wordwiseSrsMigrated', 'true');
        saveDecksToStorage();
    }
}

function loadDecksFromStorage() {
    const decksJSON = localStorage.getItem('wordwiseDecks');
    let loadedDecks = decksJSON ? JSON.parse(decksJSON) : [];
    let needsSave = false;

    const WOTD_DECK_ID = 'word_of_the_day_deck';
    const defaultWotdImage = 'https://images.unsplash.com/photo-1457369804613-52c61a468e7d?q=80&w=2070&auto=format&fit=crop';
    let wotdDeck = loadedDecks.find(d => d.id === WOTD_DECK_ID);

    if (!wotdDeck) {
        wotdDeck = {
            id: WOTD_DECK_ID,
            title: "Word of the Day",
            description: "A collection of daily words from Merriam Webster.",
            words: [],
            type: 'Vocabulary',
            isSpecial: true,
            imageUrl: defaultWotdImage,
            createdAt: new Date().toISOString()
        };
        loadedDecks.unshift(wotdDeck);
        needsSave = true;
    } else if (!wotdDeck.imageUrl) {
        wotdDeck.imageUrl = defaultWotdImage;
        needsSave = true;
    }

    loadedDecks.forEach(deck => {
        if (!deck.hasOwnProperty('folderId')) {
            deck.folderId = null;
            needsSave = true;
        }
        if (deck.words && deck.words.length > 0) {
            let deckWasMigrated = false;
            deck.words = deck.words.map(word => {
                if (typeof word === 'string' || !word.hasOwnProperty('definitions')) {
                    return createNewSrsWord(typeof word === 'string' ? word : word.text);
                }
                if (!word.definitions.mwDictionary) {
                    word.definitions.mwDictionary = null;
                    deckWasMigrated = true;
                }
                if (!word.definitions.mwThesaurus) {
                    word.definitions.mwThesaurus = null;
                    deckWasMigrated = true;
                }
                return word;
            });
            if (deckWasMigrated) needsSave = true;
        }
    });

    state.decks = loadedDecks;
    if (needsSave) {
        saveDecksToStorage();
    }
}

function saveDecksToStorage() {
    localStorage.setItem('wordwiseDecks', JSON.stringify(state.decks));
}

function loadFoldersFromStorage() {
    const foldersJSON = localStorage.getItem('wordwiseFolders');
    state.folders = foldersJSON ? JSON.parse(foldersJSON) : [];
    let needsSave = false;
    state.folders.forEach(folder => {
        if (!folder.hasOwnProperty('parentId')) {
            folder.parentId = null;
            needsSave = true;
        }
    });
    if (state.folders.length === 0) {
        state.folders = [{ id: 'f1', name: 'English', color: '#3b82f6', parentId: null }];
        needsSave = true;
    }
    if (needsSave) {
        saveFoldersToStorage();
    }
}

export function saveFoldersToStorage() {
    localStorage.setItem('wordwiseFolders', JSON.stringify(state.folders));
}

function loadProficiencyLog() {
    const logJSON = localStorage.getItem('wordwiseProficiencyLog');
    state.proficiencyLog = logJSON ? JSON.parse(logJSON) : [];
}

export function saveProficiencyLog() {
    localStorage.setItem('wordwiseProficiencyLog', JSON.stringify(state.proficiencyLog));
}

function loadAutomationSettings() {
    const settingsJSON = localStorage.getItem('wordwiseAutomationSettings');
    const defaultSettings = {
        enableImageAutomation: true,
        enableAutoDefinitions: true,
        imageAutomationDeckTypes: { Vocabulary: true, Expressions: true, Subtitle: true, blacklist: [] },
        autoDefinitionsDeckTypes: { Vocabulary: true, Expressions: true, Subtitle: true, blacklist: [] }
    };
    state.automationSettings = settingsJSON ? { ...defaultSettings, ...JSON.parse(settingsJSON) } : defaultSettings;
}

function saveAutomationSettings() {
    localStorage.setItem('wordwiseAutomationSettings', JSON.stringify(state.automationSettings));
}

function loadApiSettings() {
    const settingsJSON = localStorage.getItem('wordwiseApiSettings');
    const defaultSettings = {
        groq: true,
        gemini: true,
        merriamWebster: true,
        publicDictionary: true,
        images: true
    };
    state.apiSettings = settingsJSON ? { ...defaultSettings, ...JSON.parse(settingsJSON) } : defaultSettings;
}

function saveApiSettings() {
    localStorage.setItem('wordwiseApiSettings', JSON.stringify(state.apiSettings));
}

function loadStudySettings() {
    const settingsJSON = localStorage.getItem('wordwiseStudySettings');
    const defaultSettings = {
        prioritizeSrs: true,
        reverseFlashcards: false,
    };
    const loadedSettings = settingsJSON ? JSON.parse(settingsJSON) : {};
    state.studySettings = { ...defaultSettings, ...loadedSettings };
}

function saveStudySettings() {
    localStorage.setItem('wordwiseStudySettings', JSON.stringify(state.studySettings));
}

function loadViewStates() {
    const statesJSON = localStorage.getItem('wordwiseViewStates');
    state.viewStates = statesJSON ? JSON.parse(statesJSON) : {};
}

function saveViewStates() {
    localStorage.setItem('wordwiseViewStates', JSON.stringify(state.viewStates));
}

function loadApiKeysFromStorage() {
    state.supabaseUrl = localStorage.getItem('wordwiseSupabaseUrl') || '';
    state.supabaseAnonKey = localStorage.getItem('wordwiseSupabaseAnonKey') || '';
}

function migrateSrsData() {
    let needsSave = false;
    const oldIntervals = [1, 3, 7, 14, 30, 90, 180];
    state.decks.forEach(deck => {
        deck.words.forEach(word => {
            if (word.hasOwnProperty('masteryLevel')) {
                needsSave = true;
                const level = word.masteryLevel || 0;
                word.interval = level > 0 ? oldIntervals[Math.min(level - 1, oldIntervals.length - 1)] : 0;
                word.factor = 2.5;
                delete word.masteryLevel;
            }
        });
    });
    if (needsSave) {
        saveDecksToStorage();
    }
}

// /dataService.js
// Handles complex data fetching, parsing, and processing logic, especially involving AI.

import * as api from './api.js';
import * as state from './state.js';

/**
 * Populates a word object with definitions, translations, and images from various APIs.
 * This is a core function for automated content generation.
 * @param {object} wordObject - The word object to populate.
 * @param {object} deck - The parent deck, for context.
 * @returns {Promise<object>} The populated word object.
 */
export async function populateWordData(wordObject, deck) {
    const automationSettings = state.getAutomationSettings();
    const apiSettings = state.getApiSettings();
    const deckType = deck.type || 'Vocabulary';
    let needsSave = false;

    const isAutoDefEnabled = automationSettings.enableAutoDefinitions &&
                             automationSettings.autoDefinitionsDeckTypes[deckType] !== false &&
                             !automationSettings.autoDefinitionsDeckTypes.blacklist.includes(deck.id);

    if (isAutoDefEnabled && navigator.onLine) {
        const hasFlashcard = !!wordObject.definitions.flashcard;
        const hasDetailed = !!wordObject.definitions.detailed;
        const shouldFetchEnglishDef = (!hasFlashcard || !hasDetailed) && deckType !== 'General Study';

        if (shouldFetchEnglishDef) {
            try {
                if (deckType === 'Vocabulary' || deckType === 'Expressions') {
                    if (!apiSettings.publicDictionary) throw new Error('Public Dictionary API is disabled.');
                    const response = await fetch(`https://api.dictionaryapi.dev/api/v2/entries/en/${encodeURIComponent(wordObject.text)}`);
                    if (!response.ok) throw new Error(`Dictionary API error: ${response.status}`);
                    const data = await response.json();
                    if (!data || data.length === 0) throw new Error('No definition found.');
                    const entry = data[0];
                    const firstDefinition = entry.meanings?.[0]?.definitions?.[0]?.definition;
                    if (!firstDefinition) throw new Error('Valid entry but no definition text found.');

                    wordObject.definitions.detailed = { word: entry.word, phonetic: entry.phonetic || entry.phonetics.find(p => p.text)?.text, meanings: entry.meanings };
                    if (!wordObject.definitions.flashcard) wordObject.definitions.flashcard = firstDefinition;
                    needsSave = true;
                } else if (deckType === 'Subtitle') {
                    const explanation = await api.getExplanationFromAi(wordObject, deck);
                    wordObject.definitions.flashcard = explanation.flashcard;
                    wordObject.definitions.detailed = explanation.detailed;
                    needsSave = true;
                }
            } catch (error) {
                console.warn(`Fallback: Dictionary failed for "${wordObject.text}". Using AI. Reason: ${error.message}`);
                try {
                    const explanation = await api.getExplanationFromAi(wordObject, deck);
                    if (!wordObject.definitions.flashcard) wordObject.definitions.flashcard = explanation.flashcard;
                    if (!wordObject.definitions.detailed) wordObject.definitions.detailed = explanation.detailed;
                    if (!wordObject.example && typeof explanation.detailed === 'string') {
                        const match = explanation.detailed.match(/(?:Example:|e\.g\.)\s*"?(.+?)"?$/im);
                        if (match && match[1]) wordObject.example = match[1].trim();
                    }
                    needsSave = true;
                } catch (aiError) {
                    console.error(`FAILED to get any definition for "${wordObject.text}": ${aiError.message}`);
                }
            }
        }

        if (!wordObject.definitions.gemini && deckType !== 'General Study') {
            try {
                const amharicDef = await api.getAmharicDefinitionFromGemini(wordObject.text);
                wordObject.definitions.gemini = amharicDef;
                needsSave = true;
            } catch (error) {
                console.error(`FAILED to get Amharic definition: ${error.message}`);
            }
        }

        if (!wordObject.definitions.merriamWebster && deckType === 'Vocabulary') {
            try {
                const [dictData, thesData] = await Promise.all([
                    api.callSupabaseFunction('merriam-webster-lookup', { type: 'dictionary', word: wordObject.text.toLowerCase() }),
                    api.callSupabaseFunction('merriam-webster-lookup', { type: 'thesaurus', word: wordObject.text.toLowerCase() })
                ]);
                wordObject.definitions.merriamWebster = { dictionary: dictData, thesaurus: thesData };
                needsSave = true;
            } catch (error) {
                console.error(`FAILED to get MW data: ${error.message}`);
            }
        }
    }

    const isImageAutomationOn = automationSettings.enableImageAutomation &&
                                automationSettings.imageAutomationDeckTypes[deckType] !== false &&
                                !automationSettings.imageAutomationDeckTypes.blacklist.includes(deck.id);

    if (isImageAutomationOn && wordObject.isImageProvisional && !wordObject.imageUrl && navigator.onLine) {
        try {
            const imageResult = await api.searchUnsplash(wordObject.text);
            if (imageResult && !imageResult.error && imageResult.images.length > 0) {
                wordObject.imageUrl = imageResult.images[0].url;
                wordObject.image_query = wordObject.text;
                wordObject.isImageProvisional = true;
                needsSave = true;
            }
        } catch (error) {
            console.error(`FAILED to get provisional image: ${error.message}`);
        }
    }

    if (!wordObject.example) {
        if (deckType === 'Vocabulary' && wordObject.definitions.detailed?.meanings) {
            for (const meaning of wordObject.definitions.detailed.meanings) {
                for (const def of meaning.definitions) {
                    if (def.example) {
                        wordObject.example = def.example;
                        needsSave = true;
                        break;
                    }
                }
                if (wordObject.example) break;
            }
        }
    }

    if (needsSave) {
        state.saveDecksToStorage(); // This function is not exported, we need to fix this.
        // Let's assume a generic save function exists or the caller handles it.
        // For now, this will be a conceptual call.
        const currentDecks = state.getDecks();
        state.setDecks([...currentDecks]); // Trigger save by setting the state again
    }

    return wordObject;
}

/**
 * Filters an array of image results based on local keywords and a bulk AI safety check.
 * @param {Array<object>} images - Array of image objects from Unsplash/Google.
 * @returns {Promise<Array<object>>} A filtered array of safe images.
 */
export async function filterSafeImages(images) {
    if (!images || images.length === 0) return [];

    const forbiddenKeywords = ['bikini', 'lingerie', 'underwear', 'nude', 'naked', 'erotic', 'boudoir', 'sensual', 'provocative', 'scantily clad', 'cleavage', 'bra', 'panty'];
    const initiallyFilteredImages = images.filter(img => {
        const lowercasedDescription = (img.description || '').toLowerCase();
        return !forbiddenKeywords.some(keyword => lowercasedDescription.includes(keyword));
    });

    if (initiallyFilteredImages.length === 0) return [];

    if (!state.getSupabaseUrl() || !state.getSupabaseAnonKey()) {
        return initiallyFilteredImages;
    }

    try {
        const descriptionsForAI = initiallyFilteredImages.map((img, index) => `Image ${index}: "${img.description}"`).join('\n');
        const safetyPrompt = `You are an AI content moderator. For each image description, decide if it is "SAFE" or "UNSAFE". "UNSAFE" means any description that is NSFW, revealing, suggestive, or features swimwear/underwear.\n\n${descriptionsForAI}\n\nYou MUST respond with ONLY a valid JSON object with a single key "results", which is an array of objects. Each object must have two keys: "image_index" (number) and "status" ("SAFE" or "UNSAFE").`;
        const moderationResult = await api.getJsonFromAi([{ role: 'user', content: safetyPrompt }]);

        if (!moderationResult || !Array.isArray(moderationResult.results)) {
            return initiallyFilteredImages;
        }

        const unsafeIndexes = new Set(moderationResult.results.filter(res => res.status === 'UNSAFE').map(res => res.image_index));
        return initiallyFilteredImages.filter((img, index) => !unsafeIndexes.has(index));

    } catch (error) {
        console.error("[AI Safety] Error during bulk AI moderation:", error);
        return initiallyFilteredImages;
    }
}

/**
 * Uses AI to find the best image for a given query and context, including safety checks.
 * @param {string} query - The search term for Unsplash.
 * @param {string} context - The thematic context for the AI to consider.
 * @returns {Promise<string|null|undefined>} URL string on success, null on rejection, undefined on error.
 */
export async function getBestImageForQuery(query, context) {
    if (!state.getSupabaseUrl() || !state.getSupabaseAnonKey()) {
        return null;
    }
    try {
        const imageResults = await api.searchUnsplash(query);
        if (!imageResults.images || imageResults.images.length === 0) {
            return null;
        }
        const safeImages = await filterSafeImages(imageResults.images);
        if (safeImages.length === 0) {
            return null;
        }
        const imageDescriptions = safeImages.map((img, index) => `Image ${index}: "${img.description}" (URL: ${img.url})`).join('\n');
        const prompt = `I need to find the best image for the theme: "${context}". From the following list, choose the ONE that is the most conceptually and semantically relevant. Do not just match keywords. Respond with ONLY the full URL of the best image. If NONE are a good fit, respond with "REJECT".\n\n${imageDescriptions}`;
        const chosenUrl = await api.getGroqCompletion([{ role: 'user', content: prompt }]);
        if (chosenUrl && chosenUrl.trim().toUpperCase() !== 'REJECT' && chosenUrl.startsWith('http')) {
            return chosenUrl.trim();
        } else {
            return null;
        }
    } catch (error) {
        if (error.message.includes("API rate limit exceeded")) {
            throw error;
        }
        console.error(`Error during AI image analysis for "${query}":`, error);
        return undefined;
    }
}

