async function init() {
    // 1. Load all persisted data into the state module
    state.loadAllState();
    const { supabaseUrl, supabaseAnonKey, apiSettings, decks, folders, studySettings, automationSettings } = state;

    // Apply theme and dev tools early
    applySavedTheme();
    if (state.getIsErudaActive()) {
        if (typeof eruda !== 'undefined') {
            eruda.init();
        }
    }

    // 2. Initialize Core API module first
    api.initApi({ supabaseUrl: state.getSupabaseUrl(), supabaseAnonKey: state.getSupabaseAnonKey(), apiSettings: state.getApiSettings() });

    // 3. Initialize all other modules, passing them necessary dependencies.
    // Note: They no longer need getState or actions, as they can import from state.js and other modules.

    ui.initUIModule({
        elements: DOM,
    });

    deckManager.initDeckManager({
        elements: DOM
    });

    deckViewer.initDeckViewer({
        elements: DOM
    });

    home.initHome({
        elements: DOM
    });

    movie.initMovieModule({
        elements: DOM
    });

    quiz.initQuizModule({
        elements: DOM
    });

    chat.initChatModule({
        elements: DOM
    });

    agent.initAgent({
        // Agent still benefits from a simplified dependency injection
        actions: {
            showConfirmation: ui.showConfirmationDialog,
            onGoogleSearch: interaction.openGoogleSearchModal,
            onGetCurrentWord: deckViewer.getCurrentWord,
            saveDecks: () => state.setDecks(state.getDecks()),
            saveFolders: state.saveFoldersToStorage,
            applyFilters: deckManager.renderDeckScreen,
            openDeck: interaction.openDeck,
            addDeck: state.addDeck,
            deleteDeck: state.deleteDeck,
            updateFolders: (updatedFolders) => state.setFolders(updatedFolders),
            createNewSrsWord,
            onPopulateWordData: dataService.populateWordData,
            onGetBestImageForQuery: dataService.getBestImageForQuery
        },
        api: api,
        utils: {
            formatRelativeTime,
            calculateDeckStudyScore,
            selectNextSrsWord: selectNextWord
        }
    });

    backupManager.initBackupManager();

    wotd.initWotd({
        api: api
    });

    events.initEventListeners({
        elements: DOM
    });

    // 4. Run initial data processing and rendering
