// /utility.js
// This module contains general-purpose helper functions used across the application.

/**
 * Formats a date string into a relative time phrase (e.g., "5 min ago").
 * @param {string} dateString - The ISO date string.
 * @returns {string} The formatted relative time.
 */
export function formatRelativeTime(dateString) {
    if (!dateString) return "never";
    const date = new Date(dateString);
    const now = new Date();
    const seconds = Math.round((now - date) / 1000);
    const minutes = Math.round(seconds / 60);
    const hours = Math.round(minutes / 60);
    const days = Math.round(hours / 24);
    const months = Math.round(days / 30.44); // Average month length
    const years = Math.round(days / 365);

    if (seconds < 60) return "just now";
    if (minutes < 60) return `${minutes} min ago`;
    if (hours < 24) return `${hours} hr ago`;
    if (days < 30) return `${days} day${days > 1 ? 's' : ''} ago`;
    if (months < 12) return `${months} mo ago`;
    return `${years} yr ago`;
}

/**
 * Truncates a string in the middle, adding an ellipsis.
 * @param {string} text - The text to truncate.
 * @param {number} maxLength - The maximum desired length.
 * @returns {string} The truncated string.
 */
export function truncateInMiddle(text, maxLength) {
    if (!text || text.length <= maxLength) {
        return text;
    }
    const ellipsis = '...';
    const charsToShow = maxLength - ellipsis.length;
    const frontChars = Math.ceil(charsToShow / 2);
    const backChars = Math.floor(charsToShow / 2);

    return text.substring(0, frontChars) + ellipsis + text.substring(text.length - backChars);
}

/**
 * Converts SRT time format (HH:MM:SS,ms) to seconds.
 * @param {string} timeStr - The SRT time string.
 * @returns {number} The time in seconds.
 */
export function srtTimeToSeconds(timeStr) {
    if (!timeStr) return 0;
    const parts = timeStr.split(/[:,]/);
    const hours = parseInt(parts[0], 10) || 0;
    const minutes = parseInt(parts[1], 10) || 0;
    const seconds = parseInt(parts[2], 10) || 0;
    const milliseconds = parseInt(parts[3], 10) || 0;
    return (hours * 3600) + (minutes * 60) + seconds + (milliseconds / 1000);
}

/**
 * Converts seconds to SRT time format (HH:MM:SS,ms).
 * @param {number} totalSeconds - The time in seconds.
 * @returns {string|null} The SRT time string or null if input is invalid.
 */
export function secondsToSrtTime(totalSeconds) {
    if (typeof totalSeconds !== 'number' || isNaN(totalSeconds)) return null;
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = Math.floor(totalSeconds % 60);
    const milliseconds = Math.round((totalSeconds - Math.floor(totalSeconds)) * 1000);

    return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')},${String(milliseconds).padStart(3, '0')}`;
}

/**
 * A simple debouncing function.
 * @param {function} func - The function to debounce.
 * @param {number} wait - The debounce delay in milliseconds.
 * @returns {function} The debounced function.
 */
export function debounce(func, wait) {
    let timeout;
    return function executedFunction(...args) {
        const later = () => {
            clearTimeout(timeout);
            func(...args);
        };
        clearTimeout(timeout);
        timeout = setTimeout(later, wait);
    };
}

