        setPadding(10, 40, 0, 10)
        setTypeface(null, android.graphics.Typeface.BOLD)
    }
}

private fun createGlassCard(title: String, value: String, isProgress: Boolean = false): View {
    return LinearLayout(context).apply {
        orientation = LinearLayout.VERTICAL
        setPadding(40, 40, 40, 40)
        background = getGlassDrawable()
        layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.WRAP_CONTENT).apply {
            setMargins(0, 0, 0, 30)
        }

        addView(TextView(context).apply {
            text = title
            textSize = 10f
            setTextColor(COL_TEXT_MUTED)
            letterSpacing = 0.15f
        })

        if (isProgress) {
             // Simple Progress Bar Simulation
             addView(ProgressBar(context, null, android.R.attr.progressBarStyleHorizontal).apply {
                 progress = 75
                 scaleY = 2f
                 setPadding(0, 20, 0, 0)
                 progressTintList = android.content.res.ColorStateList.valueOf(COL_ACCENT_CYAN)
             })
             addView(TextView(context).apply {
                 text = value
                 textSize = 12f
                 setTextColor(Color.WHITE)
                 setPadding(0, 10, 0, 0)
             })
        } else {
            addView(TextView(context).apply {
                text = value
                textSize = 16f
                setTextColor(Color.WHITE)
                setTypeface(null, android.graphics.Typeface.BOLD)
                setPadding(0, 15, 0, 0)
            })
