}

private fun createGaugeCard(title: String, valueStr: String, pct: Int, color: Int): View {
    return LinearLayout(context).apply {
        orientation = LinearLayout.VERTICAL
        gravity = Gravity.CENTER
        background = getGlassDrawable()
        layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f).apply {
            setMargins(10, 0, 10, 30)
        }
        setPadding(30, 40, 30, 40)

        addView(TextView(context).apply {
            text = title
            textSize = 10f
            setTextColor(COL_TEXT_MUTED)
        })

        // Custom Circular Gauge
        addView(GaugeView(context, color, pct).apply {
            layoutParams = LinearLayout.LayoutParams(150, 150).apply {
                 setMargins(0, 30, 0, 20)
            }
        })

        addView(TextView(context).apply {
            text = valueStr
            textSize = 14f
            setTextColor(Color.WHITE)
            setTypeface(null, android.graphics.Typeface.BOLD)
        })
