private fun getGlassDrawable(radius: Float = 30f, bgColor: Int = COL_GLASS): GradientDrawable {
    return GradientDrawable().apply {
        color = android.content.res.ColorStateList.valueOf(bgColor)
        cornerRadius = radius
        setStroke(2, 0x1AFFFFFF.toInt())
    }
}

// --- CUSTOM GAUGE VIEW ---
class GaugeView(context: Context, val color: Int, val pct: Int) : View(context) {
    private val paint = Paint(Paint.ANTI_ALIAS_FLAG)
    private val rect = RectF()

    override fun onDraw(canvas: Canvas) {
        super.onDraw(canvas)
        val stroke = 15f
        val s = width.coerceAtMost(height).toFloat() - stroke
        rect.set(stroke/2, stroke/2, s, s)

        // Background Ring
        paint.style = Paint.Style.STROKE
        paint.strokeWidth = stroke
        paint.color = 0x33FFFFFF.toInt()
        canvas.drawArc(rect, 0f, 360f, false, paint)

        // Progress Ring
        paint.color = color
        paint.strokeCap = Paint.Cap.ROUND
        canvas.drawArc(rect, -90f, (3.6f * pct), false, paint)
    }
}

// --- DATA FETCHERS (Helper to simplify Dash) ---
private fun getRamInfo(ctx: Context): Pair<String, Int> {
    val actManager = ctx.getSystemService(Context.ACTIVITY_SERVICE) as android.app.ActivityManager
    val memInfo = android.app.ActivityManager.MemoryInfo()
    actManager.getMemoryInfo(memInfo)
    val total = memInfo.totalMem / (1024 * 1024)
    val avail = memInfo.availMem / (1024 * 1024)
    val used = total - avail
    val pct = ((used.toFloat() / total.toFloat()) * 100).toInt()
    return Pair("$used / $total MB", pct)
}

private fun getBatterySimple(ctx: Context): Pair<String, Int> {
    val batt = ctx.registerReceiver(null, android.content.IntentFilter(android.content.Intent.ACTION_BATTERY_CHANGED))
    val level = batt?.getIntExtra(android.os.BatteryManager.EXTRA_LEVEL, 0) ?: 0
    val status = batt?.getIntExtra(android.os.BatteryManager.EXTRA_STATUS, -1) ?: -1
    val isCharging = status == android.os.BatteryManager.BATTERY_STATUS_CHARGING
    return Pair("$level% ${if(isCharging) "⚡" else ""}", level)
}

private fun getStorageSimple(ctx: Context): String {
    val dataDir = android.os.Environment.getDataDirectory()
    val stat = android.os.StatFs(dataDir.path)
    val total = (stat.blockCountLong * stat.blockSizeLong) / (1024 * 1024 * 1024)
    val free = (stat.availableBlocksLong * stat.blockSizeLong) / (1024 * 1024 * 1024)
    return "${total-free} GB Used / $total GB Total"
}

