// /stateManager.js
// Centralized module for loading from and saving to localStorage.

import { createNewSrsWord } from './srs.js';

// --- Internal Migration Helpers ---

function migrateSrsData(decks) {
    let needsSave = false;
    const oldIntervals = [1, 3, 7, 14, 30, 90, 180];

    decks.forEach(deck => {
        deck.words.forEach(word => {
            if (word.hasOwnProperty('masteryLevel')) {
                needsSave = true;
                const level = word.masteryLevel || 0;
                word.interval = level > 0 ? oldIntervals[Math.min(level - 1, oldIntervals.length - 1)] : 0;
                word.factor = 2.5;
                delete word.masteryLevel;
            }
        });
    });
    return { decks, needsSave };
}

// --- Deck & Folder Management ---

export function loadDecks() {
    const decksJSON = localStorage.getItem('wordwiseDecks');
    let loadedDecks = decksJSON ? JSON.parse(decksJSON) : [];
    let needsSave = false;

    const WOTD_DECK_ID = 'word_of_the_day_deck';
    const defaultWotdImage = 'https://images.unsplash.com/photo-1457369804613-52c61a468e7d?q=80&w=2070&auto=format&fit=crop';
    let wotdDeck = loadedDecks.find(d => d.id === WOTD_DECK_ID);

    if (!wotdDeck) {
        console.log("📚 [WotD Deck] 'Word of the Day' deck not found. Creating it.");
        wotdDeck = {
            id: WOTD_DECK_ID, title: "Word of the Day",
            description: "A collection of daily words from Merriam Webster.",
            words: [], type: 'Vocabulary', isSpecial: true,
            imageUrl: defaultWotdImage, createdAt: new Date().toISOString()
        };
        loadedDecks.unshift(wotdDeck);
        needsSave = true;
    } else if (!wotdDeck.imageUrl) {
        console.log("🖼️ [WotD Deck] Assigning default cover to existing WotD deck.");
        wotdDeck.imageUrl = defaultWotdImage;
        needsSave = true;
    }

    loadedDecks.forEach(deck => {
        if (!deck.hasOwnProperty('folderId')) {
            deck.folderId = null;
            needsSave = true;
        }
        if (deck.words && deck.words.length > 0) {
            let deckWasMigrated = false;
            deck.words = deck.words.map(word => {
                if (typeof word === 'string' || !word.hasOwnProperty('definitions')) {
                    deckWasMigrated = true;
                    const wordText = typeof word === 'string' ? word : word.text;
                    return { ...createNewSrsWord(wordText), masteryLevel: word.masteryLevel, lastSeen: word.lastSeen };
                }
                if (!word.definitions.mwDictionary) { word.definitions.mwDictionary = null; deckWasMigrated = true; }
                if (!word.definitions.mwThesaurus) { word.definitions.mwThesaurus = null; deckWasMigrated = true; }
                return word;
            });
            if (deckWasMigrated) needsSave = true;
        }
    });

    // New SRS migration check
    if (!localStorage.getItem('wordwiseSrsMigrated')) {
        const migrationResult = migrateSrsData(loadedDecks);
        loadedDecks = migrationResult.decks;
        if (migrationResult.needsSave) {
            needsSave = true;
            localStorage.setItem('wordwiseSrsMigrated', 'true');
        }
    }

    if (needsSave) {
        saveDecks(loadedDecks);
    }
    return loadedDecks;
}

export function saveDecks(decks) {
    localStorage.setItem('wordwiseDecks', JSON.stringify(decks));
}

export function loadFolders() {
    const foldersJSON = localStorage.getItem('wordwiseFolders');
    let folders = foldersJSON ? JSON.parse(foldersJSON) : [];
    let needsSave = false;
    folders.forEach(folder => {
        if (!folder.hasOwnProperty('parentId')) {
            folder.parentId = null;
            needsSave = true;
        }
    });
    if (folders.length === 0) {
        folders = [{ id: 'f1', name: 'English', color: '#3b82f6', parentId: null }];
        needsSave = true;
    }
    if (needsSave) {
        saveFolders(folders);
    }
    return folders;
}

export function saveFolders(folders) {
    localStorage.setItem('wordwiseFolders', JSON.stringify(folders));
}

// --- Settings Management ---

export function loadAutomationSettings() {
    const settingsJSON = localStorage.getItem('wordwiseAutomationSettings');
    const defaultSettings = {
        enableImageAutomation: true, enableAutoDefinitions: true,
        imageAutomationDeckTypes: { Vocabulary: true, Expressions: true, Subtitle: true, blacklist: [] },
        autoDefinitionsDeckTypes: { Vocabulary: true, Expressions: true, Subtitle: true, blacklist: [] }
    };
    return settingsJSON ? { ...defaultSettings, ...JSON.parse(settingsJSON) } : defaultSettings;
}

export function saveAutomationSettings(settings) {
    localStorage.setItem('wordwiseAutomationSettings', JSON.stringify(settings));
}

export function loadApiSettings() {
    const settingsJSON = localStorage.getItem('wordwiseApiSettings');
    const defaultSettings = { groq: true, gemini: true, merriamWebster: true, publicDictionary: true, images: true };
    return settingsJSON ? { ...defaultSettings, ...JSON.parse(settingsJSON) } : defaultSettings;
}

export function saveApiSettings(settings) {
    localStorage.setItem('wordwiseApiSettings', JSON.stringify(settings));
}

export function loadStudySettings() {
    const settingsJSON = localStorage.getItem('wordwiseStudySettings');
    const defaultSettings = { prioritizeSrs: true, reverseFlashcards: false };
    const loadedSettings = settingsJSON ? JSON.parse(settingsJSON) : {};
    return { ...defaultSettings, ...loadedSettings };
}

export function saveStudySettings(settings) {
    localStorage.setItem('wordwiseStudySettings', JSON.stringify(settings));
}

// --- User Data & Credentials ---

export function loadProficiencyLog() {
    const logJSON = localStorage.getItem('wordwiseProficiencyLog');
    return logJSON ? JSON.parse(logJSON) : [];
}

export function saveProficiencyLog(log) {
    localStorage.setItem('wordwiseProficiencyLog', JSON.stringify(log));
}

export function loadApiKeys() {
    return {
        supabaseUrl: localStorage.getItem('wordwiseSupabaseUrl') || '',
        supabaseAnonKey: localStorage.getItem('wordwiseSupabaseAnonKey') || ''
    };
}

export function saveCredential(key, name) {
    localStorage.setItem(`wordwise${name}`, key);
}

// --- UI Preferences ---

export function loadViewStates() {
    const statesJSON = localStorage.getItem('wordwiseViewStates');
    return statesJSON ? JSON.parse(statesJSON) : {};
}

export function saveViewStates(states) {
    localStorage.setItem('wordwiseViewStates', JSON.stringify(states));
}

export function loadDefaultDeckView() {
    return localStorage.getItem('wordwiseDefaultDeckView') || 'flashcard';
}

export function saveDefaultDeckView(mode) {
    localStorage.setItem('wordwiseDefaultDeckView', mode);
}

export function loadTheme() {
    return localStorage.getItem('wordwiseTheme');
}

export function saveTheme(theme) {
    localStorage.setItem('wordwiseTheme', theme);
}

// --- Dev & System State ---

export function isBackendSettingsVisible() {
    return localStorage.getItem('wordwiseBackendSettingsVisible') === 'true';
}

export function setBackendSettingsVisible(isVisible) {
    localStorage.setItem('wordwiseBackendSettingsVisible', isVisible);
}

export function isErudaActive() {
    return localStorage.getItem('wordwiseErudaActive') === 'true';
}

export function setErudaActive(isActive) {
    localStorage.setItem('wordwiseErudaActive', isActive);
}

