/**
 * Parses SRT subtitle content into an array of objects.
 * @param {string} srtContent - The raw SRT string.
 * @returns {Promise<Array<{number: string, timestamp: string, text: string}>>}
 */
export async function parseSrt(srtContent) {
    if (!srtContent) return [];

    const toastId = 'srt-parser-toast';

    function simpleParse(content) {
        const lines = content.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
        const subtitles = [];
        let i = 0;
        while (i < lines.length) {
            const number = lines[i];
            const timestamp = lines[i + 1];
            if (number && timestamp && timestamp.includes('-->')) {
                let textLines = [];
                let j = i + 2;
                while (lines[j] && lines[j].trim() !== '') {
                    textLines.push(lines[j]);
                    j++;
                }
                const text = textLines.join(' ').replace(/<[^>]+>/g, '').trim();
                if (text) {
                    subtitles.push({ number, timestamp: timestamp.split(' --> ')[0], text });
                }
                i = j + 1;
            } else {
                i++;
            }
        }
        return subtitles;
    }

    actions.showToast("Parsing SRT file...", false, toastId, true);
    console.log("[SRT Parser] Phase 1: Starting initial simple parse.");
    let initialResult = simpleParse(srtContent);

    const isLikelyMisparsed = initialResult.length > 0 && initialResult[0].text.length > 200;

    if (!isLikelyMisparsed) {
        console.log(`[SRT Parser] SUCCESS: Simple parse successful with ${initialResult.length} lines.`);
        actions.hideToast(toastId);
        actions.showToast("SRT parsed successfully!", false);
        return initialResult;
    }

    actions.showToast("File seems malformed. Attempting to self-heal...", false, toastId, true);
    console.warn("[SRT Parser] Phase 2: Heuristic check failed. Starting advanced self-healing process.");

    const allLines = srtContent.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
    let firstValidLineIndex = -1;
    let pattern = { hasNumberLine: false };

    for (let i = 0; i < allLines.length; i++) {
        if (allLines[i] && allLines[i].includes('-->')) {
            pattern.hasNumberLine = (i > 0 && /^\d+$/.test(allLines[i-1].trim()));
            firstValidLineIndex = pattern.hasNumberLine ? i - 1 : i;
            break;
        }
    }

    if (firstValidLineIndex === -1) {
        console.error("[SRT Parser] FAILURE: Could not find any valid timestamp pattern. Aborting advanced parse.");
        actions.hideToast(toastId);
        actions.showToast("Could not parse SRT file. Displaying best attempt.", true);
        return initialResult;
    }

    const malformedHeader = allLines.slice(0, firstValidLineIndex).join('\n').trim();
    const cleanSrtBody = allLines.slice(firstValidLineIndex).join('\n');
    let healedResult = simpleParse(cleanSrtBody);

    if (malformedHeader) {
        const { supabaseUrl, supabaseAnonKey } = getState();
        if (supabaseUrl && supabaseAnonKey && navigator.onLine) {
            actions.showToast("Using AI to correct file header...", false, toastId, true);
            console.log("[SRT Parser] Phase 4: Attempting AI correction for malformed header...");
            try {
                const exampleGoodBlock = allLines.slice(firstValidLineIndex, firstValidLineIndex + 4).join('\n');
                const prompt = `You are a subtitle file repair expert. The following text is a corrupted header from an SRT file. Fix it to match the standard SRT block format. Each block should have a number, a timestamp, and text. Do not add any extra text or explanations. Just output the corrected blocks.\n\nCorrect Format Example:\n${exampleGoodBlock}\n\nCorrupted Text to Fix:\n---\n${malformedHeader}\n---`;
                const correctedHeader = await actions.getGroqCompletion([{ role: 'user', content: prompt }]);
                const aiFixedSubs = simpleParse(correctedHeader);

                if (aiFixedSubs.length > 0) {
                    healedResult = [...aiFixedSubs, ...healedResult];
                    console.log(`[SRT Parser] AI SUCCESS: AI successfully corrected ${aiFixedSubs.length} header block(s).`);
                    actions.showToast("AI correction successful!", false, toastId);
                } else {
                    console.warn("[SRT Parser] AI ran but did not produce valid subtitle blocks.");
                }
            } catch (aiError) {
                console.error("[SRT Parser] AI FAILURE: AI correction failed:", aiError);
                actions.showToast("AI correction failed. Using partial result.", true, toastId);
            }
        }
    }

    healedResult.forEach((sub, index) => {
        sub.number = String(index + 1);
    });

    actions.hideToast(toastId);
    actions.showToast(`Advanced parse complete! Found ${healedResult.length} lines.`, false);
    return healedResult;
}

/**
 * Uses AI to extract advanced vocabulary from a movie's subtitles and creates a new deck.
 * @param {object} movie - The movie object.
 */
export async function createSmartDeckFromMovie(movie) {
    const loadingToastId = 'smart-deck-loader';
    actions.showToast("AI is analyzing subtitles...", false, loadingToastId, true);

    try {
        const prompt = `You are an expert ESL/EFL linguist who creates advanced learning materials from authentic media. Your task is to analyze the provided movie subtitles and extract lines suitable for a learner who has already mastered intermediate English.\n\nFrom the subtitles for "${movie.title}", extract at least 40 lines that meet one or more of these criteria:\n1. **Advanced Vocabulary:** Words rarely used in casual speech but natural in high-level dialogue.\n2. **Complex Idioms/Phrasal Verbs:** Sophisticated expressions, not beginner-level clichés.\n3. **Rare or Sophisticated Collocations:** Natural but challenging word pairings.\n4. **Nuanced Tone/Style:** Lines demonstrating subtle emotion, irony, or high-level conversational style.\n5. **Advanced Contractions/Reductions:** Rare or nuanced spoken forms.\n\n**Instructions for each extracted line:**\n- Create a \`card_text\` by slightly cleaning up the original line for a flashcard (e.g., remove stutters like "uhm").\n- Provide an \`explanation\` that deconstructs *why* the line is advanced. Define the specific word, explain the idiom, or analyze the tone. **Focus only on the language, not the movie's plot.**\n- Include the \`original_line\` for context.\n- **CRITICAL:** You must also include the original \`original_line_number\` that was provided with the subtitle.\n\nYou MUST respond with ONLY a valid JSON object. The object must have a single key "advanced_lines", which is an array of objects. Each object must have three string keys (\`card_text\`, \`explanation\`, \`original_line\`) and one number key (\`original_line_number\`).\n\nDo not include any text or explanations outside of this JSON structure.\n\nHere are the subtitles (Format: Number, Text):\n---\n---\n${movie.srtContent}\n---`;

        // Note: Using actions.api.getGeminiCompletion via the passed actions
        const responseText = await actions.api.getGeminiCompletion([{ role: 'user', parts: [{ text: prompt }] }]);

        const jsonMatch = responseText.match(/```json\n([\s\S]*?)\n```|({[\s\S]*})/);
        if (!jsonMatch) {
            throw new Error("AI did not return a recognizable JSON object.");
        }

        const jsonString = jsonMatch[1] || jsonMatch[2];
        const aiData = JSON.parse(jsonString);

        if (!aiData.advanced_lines || !Array.isArray(aiData.advanced_lines)) {
             throw new Error("AI response is missing the 'advanced_lines' array.");
        }

        // Create a fast lookup map to find timestamps by line number
        const subtitleMap = new Map(movie.subtitles.map(sub => [String(sub.number), sub.timestamp]));

        const newCards = aiData.advanced_lines.map(item => {
            // Uses the injected action to create a word
            const newWord = actions.createNewSrsWord(item.card_text);
            newWord.definitions.flashcard = item.explanation;
            newWord.definitions.detailed = item.explanation;
            newWord.example = item.original_line;
            newWord.note = `From "${movie.title}"`;

            if (item.original_line_number) {
                newWord.timestamp = subtitleMap.get(String(item.original_line_number));
            }

            return newWord;
        });

        const newSmartDeck = {
            id: 'deck_' + movie.id,
            title: movie.title,
            description: `AI-generated advanced dialogue from the movie ${movie.title}.`,
            words: newCards,
            type: 'Subtitle',
            imageUrl: movie.poster,
            is_ai_generated: true,
            createdAt: new Date().toISOString(),
            lastSeen: null
        };

        actions.addDeck(newSmartDeck);
        actions.hideToast(loadingToastId);
        actions.showToast(`Smart Deck for "${movie.title}" created with ${newCards.length} lines!`);
        actions.openDeck(newSmartDeck);

    } catch (error) {
        console.error("Error creating Smart Deck:", error);
        actions.hideToast(loadingToastId);
        actions.showToast(`Failed to create Smart Deck: ${error.message}`, true);
    }
}

