// /settingsManager.js
// Manages all user preferences and configuration persistence.

let automationSettings = {};
let studySettings = {};
let apiSettings = {};

const DEFAULTS = {
    automation: {
        enableImageAutomation: true,
        enableAutoDefinitions: true,
        imageAutomationDeckTypes: { Vocabulary: true, Expressions: true, Subtitle: true, blacklist: [] },
        autoDefinitionsDeckTypes: { Vocabulary: true, Expressions: true, Subtitle: true, blacklist: [] }
    },
    study: {
        prioritizeSrs: true,
        reverseFlashcards: false,
    },
    api: {
        groq: true,
        gemini: true,
        merriamWebster: true,
        publicDictionary: true,
        images: true
    }
};

export function initSettings() {
    loadAutomationSettings();
    loadStudySettings();
    loadApiSettings();
    console.log("Settings Manager initialized.");
}

// --- Automation Settings ---

function loadAutomationSettings() {
    const json = localStorage.getItem('wordwiseAutomationSettings');
    automationSettings = json ? { ...DEFAULTS.automation, ...JSON.parse(json) } : JSON.parse(JSON.stringify(DEFAULTS.automation));
}

export function getAutomationSettings() {
    return automationSettings;
}

export function saveAutomationSettings(newSettings) {
    if (newSettings) automationSettings = newSettings;
    localStorage.setItem('wordwiseAutomationSettings', JSON.stringify(automationSettings));
}

export function setAutomationSetting(key, value) {
    automationSettings[key] = value;
    saveAutomationSettings();
}

export function toggleDeckTypeSetting(featureKey, deckType) {
    if (automationSettings[featureKey]) {
        automationSettings[featureKey][deckType] = !automationSettings[featureKey][deckType];
        saveAutomationSettings();
    }
}

export function updateBlacklist(featureKey, blacklist) {
    if (automationSettings[featureKey]) {
        automationSettings[featureKey].blacklist = blacklist;
        saveAutomationSettings();
    }
}

// --- Study Settings ---

function loadStudySettings() {
    const json = localStorage.getItem('wordwiseStudySettings');
    studySettings = json ? { ...DEFAULTS.study, ...JSON.parse(json) } : JSON.parse(JSON.stringify(DEFAULTS.study));
}

export function getStudySettings() {
    return studySettings;
}

export function saveStudySettings(newSettings) {
    if (newSettings) studySettings = newSettings;
    localStorage.setItem('wordwiseStudySettings', JSON.stringify(studySettings));
}

// --- API Settings ---

function loadApiSettings() {
    const json = localStorage.getItem('wordwiseApiSettings');
    apiSettings = json ? { ...DEFAULTS.api, ...JSON.parse(json) } : JSON.parse(JSON.stringify(DEFAULTS.api));
}

export function getApiSettings() {
    return apiSettings;
}

export function saveApiSettings(newSettings) {
    if (newSettings) apiSettings = newSettings;
    localStorage.setItem('wordwiseApiSettings', JSON.stringify(apiSettings));
}

export function setApiSetting(key, value) {
    apiSettings[key] = value;
    saveApiSettings();
}

