/**
 * Parses SRT subtitle content into an array of objects.
 * @param {string} srtContent - The raw SRT string.
 * @returns {Promise<Array>} Array of subtitle objects { number, timestamp, text }.
 */
export async function parseSrt(srtContent) {
    if (!srtContent) return [];

    const toastId = 'srt-parser-toast';

    // --- Phase 1: Initial Simple Parse ---
    function simpleParse(content) {
        const lines = content.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
        const subtitles = [];
        let i = 0;
        while (i < lines.length) {
            const number = lines[i];
            const timestamp = lines[i + 1];
            if (number && timestamp && timestamp.includes('-->')) {
                let textLines = [];
                let j = i + 2;
                while (lines[j] && lines[j].trim() !== '') {
                    textLines.push(lines[j]);
                    j++;
                }
                const text = textLines.join(' ').replace(/<[^>]+>/g, '').trim();
                if (text) {
                    subtitles.push({ number, timestamp: timestamp.split(' --> ')[0], text });
                }
                i = j + 1;
            } else {
                i++;
            }
        }
        return subtitles;
    }

    actions.showToast("Parsing SRT file...", false, toastId, true);
    console.log("[SRT Parser] Phase 1: Starting initial simple parse.");
    let initialResult = simpleParse(srtContent);

    // --- Phase 2: Heuristic Check ---
    const isLikelyMisparsed = initialResult.length > 0 && initialResult[0].text.length > 200;

    if (!isLikelyMisparsed) {
        console.log(`[SRT Parser] SUCCESS: Simple parse successful with ${initialResult.length} lines.`);
        actions.hideToast(toastId);
        return initialResult;
    }

    // --- Phase 3: Advanced Pattern Detection ---
    actions.showToast("File seems malformed. Attempting to self-heal...", false, toastId, true);
    console.warn("[SRT Parser] Phase 2: Heuristic check failed. Starting advanced self-healing process.");

    const allLines = srtContent.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
    let firstValidLineIndex = -1;
    let pattern = { hasNumberLine: false };

    for (let i = 0; i < allLines.length; i++) {
        if (allLines[i] && allLines[i].includes('-->')) {
            pattern.hasNumberLine = (i > 0 && /^\d+$/.test(allLines[i-1].trim()));
            firstValidLineIndex = pattern.hasNumberLine ? i - 1 : i;
            break;
        }
    }

    if (firstValidLineIndex === -1) {
        console.error("[SRT Parser] FAILURE: Could not find any valid timestamp pattern.");
        actions.hideToast(toastId);
        actions.showToast("Could not parse SRT file. Displaying best attempt.", true);
        return initialResult;
    }

    const malformedHeader = allLines.slice(0, firstValidLineIndex).join('\n').trim();
    const cleanSrtBody = allLines.slice(firstValidLineIndex).join('\n');
    let healedResult = simpleParse(cleanSrtBody);

    // --- Phase 4: AI Fallback ---
    if (malformedHeader) {
        const { supabaseUrl, supabaseAnonKey } = getState();
        if (supabaseUrl && supabaseAnonKey && navigator.onLine) {
            actions.showToast("Using AI to correct file header...", false, toastId, true);
            try {
                const exampleGoodBlock = allLines.slice(firstValidLineIndex, firstValidLineIndex + 4).join('\n');
                const prompt = `You are a subtitle file repair expert. Fix this corrupted SRT header. Output ONLY the corrected blocks.\n\nCorrect Example:\n${exampleGoodBlock}\n\nCorrupted:\n---\n${malformedHeader}\n---`;

                // Use the API module directly since we are inside movie.js which has access to actions.api or we need to pass it
                // 'actions' is available in module scope.
                const correctedHeader = await actions.getGroqCompletion([{ role: 'user', content: prompt }]);
                const aiFixedSubs = simpleParse(correctedHeader);

                if (aiFixedSubs.length > 0) {
                    healedResult = [...aiFixedSubs, ...healedResult];
                    actions.showToast("AI correction successful!", false, toastId);
                }
            } catch (aiError) {
                console.error("[SRT Parser] AI correction failed:", aiError);
            }
        }
    }

    // --- Phase 5: Final Renumbering ---
    healedResult.forEach((sub, index) => {
        sub.number = String(index + 1);
    });

    actions.hideToast(toastId);
    return healedResult;
}

/**
 * Filters a list of images for safety using keywords and AI.
 * @param {Array} images - Array of image objects from Unsplash/Google.
 * @returns {Promise<Array>} Filtered array of safe images.
 */
export async function filterSafeImages(images) {
    if (!images || images.length === 0) return [];

    // 1. Fast local keyword filtering
    const forbiddenKeywords = [
        'bikini', 'lingerie', 'underwear', 'nude', 'naked', 'erotic',
        'boudoir', 'sensual', 'provocative', 'scantily clad', 'cleavage', 'bra', 'panty'
    ];

    const initiallyFilteredImages = images.filter(img => {
        const lowercasedDescription = (img.description || '').toLowerCase();
        for (const keyword of forbiddenKeywords) {
            if (lowercasedDescription.includes(keyword)) return false;
        }
        return true;
    });

    if (initiallyFilteredImages.length === 0) return [];

    // 2. Bulk AI check
    // Note: We access keys via the module-level apiKeys object which is set in initApi
    if (!apiKeys.supabaseUrl || !apiKeys.supabaseAnonKey) {
        return initiallyFilteredImages;
    }

    try {
        const descriptionsForAI = initiallyFilteredImages.map((img, index) => 
            `Image ${index}: "${img.description}"`
        ).join('\n');

        const safetyPrompt = `You are an AI content moderator. Decide if these images are "SAFE" or "UNSAFE". UNSAFE means NSFW, revealing, suggestive, or swimwear/underwear.\n\n${descriptionsForAI}\n\nRespond ONLY with a valid JSON object: { "results": [ { "image_index": number, "status": "SAFE" | "UNSAFE" } ] }`;

        // We call getJsonFromAi from within this module
        const moderationResult = await getJsonFromAi([{ role: 'user', content: safetyPrompt }]);

        if (!moderationResult || !Array.isArray(moderationResult.results)) {
            return initiallyFilteredImages;
        }

        const unsafeIndexes = new Set(
            moderationResult.results
                .filter(res => res.status === 'UNSAFE')
                .map(res => res.image_index)
        );

        return initiallyFilteredImages.filter((img, index) => !unsafeIndexes.has(index));

    } catch (error) {
        console.error("[AI Safety] Error during bulk AI moderation:", error);
        return initiallyFilteredImages;
    }
}

