export async function createSmartDeckFromMovie(movie) {
    const loadingToastId = 'smart-deck-loader';
    actions.showToast("AI is analyzing subtitles...", false, loadingToastId, true);

    try {
        const prompt = `You are an expert ESL/EFL linguist who creates advanced learning materials from authentic media. Your task is to analyze the provided movie subtitles and extract lines suitable for a learner who has already mastered intermediate English.\n\nFrom the subtitles for "${movie.title}", extract at least 40 lines that meet one or more of these criteria:\n1.  **Advanced Vocabulary:** Words rarely used in casual speech but natural in high-level dialogue.\n2.  **Complex Idioms/Phrasal Verbs:** Sophisticated expressions, not beginner-level clichés.\n3.  **Rare or Sophisticated Collocations:** Natural but challenging word pairings.\n4.  **Nuanced Tone/Style:** Lines demonstrating subtle emotion, irony, or high-level conversational style.\n5.  **Advanced Contractions/Reductions:** Rare or nuanced spoken forms.\n\n**Instructions for each extracted line:**\n- Create a \`card_text\` by slightly cleaning up the original line for a flashcard (e.g., remove stutters like "uhm").\n- Provide an \`explanation\` that deconstructs *why* the line is advanced. Define the specific word, explain the idiom, or analyze the tone. **Focus only on the language, not the movie's plot.**\n- Include the \`original_line\` for context.\n- **CRITICAL:** You must also include the original \`original_line_number\` that was provided with the subtitle.\n\nYou MUST respond with ONLY a valid JSON object. The object must have a single key "advanced_lines", which is an array of objects. Each object must have three string keys (\`card_text\`, \`explanation\`, \`original_line\`) and one number key (\`original_line_number\`).\n\nDo not include any text or explanations outside of this JSON structure.\n\nHere are the subtitles (Format: Number, Text):\n---\n---\n${movie.srtContent}\n---`;

        const responseText = await actions.api.getGeminiCompletion([{ role: 'user', parts: [{ text: prompt }] }]);

        const jsonMatch = responseText.match(/```json\n([\s\S]*?)\n```|({[\s\S]*})/);
        if (!jsonMatch) {
            throw new Error("AI did not return a recognizable JSON object.");
        }

        const jsonString = jsonMatch[1] || jsonMatch[2];
        const aiData = JSON.parse(jsonString);

        if (!aiData.advanced_lines || !Array.isArray(aiData.advanced_lines)) {
             throw new Error("AI response is missing the 'advanced_lines' array.");
        }

        const subtitleMap = new Map(movie.subtitles.map(sub => [String(sub.number), sub.timestamp]));

        const newCards = aiData.advanced_lines.map(item => {
            const newWord = actions.createPlaceholderWordObjects([item.card_text])[0];
            newWord.definitions.flashcard = item.explanation;
            newWord.definitions.detailed = item.explanation;
            newWord.example = item.original_line;
            newWord.note = `From "${movie.title}"`;

            if (item.original_line_number) {
                newWord.timestamp = subtitleMap.get(String(item.original_line_number));
            }

            return newWord;
        });

        const newSmartDeck = {
            id: 'deck_' + movie.id,
            title: movie.title,
            description: `AI-generated advanced dialogue from the movie ${movie.title}.`,
            words: newCards,
            type: 'Subtitle',
            imageUrl: movie.poster,
            is_ai_generated: true,
            createdAt: new Date().toISOString(),
            lastSeen: null
        };

        actions.addDeck(newSmartDeck);
        actions.hideToast(loadingToastId);
        actions.showToast(`Smart Deck for "${movie.title}" created with ${newCards.length} lines!`);

        if (newSmartDeck) {
             actions.openDeck(newSmartDeck);
        }

    } catch (error) {
        console.error("Error creating Smart Deck:", error);
        actions.hideToast(loadingToastId);
        actions.showToast(`Failed to create Smart Deck: ${error.message}`, true);
    }
}

export async function handleUploadDeck(deckId) {
    console.log(`[Upload] Starting upload process for deck ID: ${deckId}`);
    const { decks, supabaseUrl, supabaseAnonKey } = getState();
    const deckToUpload = decks.find(d => d.id === deckId);
    if (!deckToUpload) {
        actions.ui.showToast("Could not find the deck to upload.", true);
        return;
    }

    if (!deckToUpload.description) {
        actions.ui.showToast("Please add a description to this deck before uploading.", true);
        return;
    }
    if (!deckToUpload.imageUrl) {
        actions.ui.showToast("Please assign a cover image to this deck before uploading.", true);
        return;
    }
    if (!deckToUpload.words || deckToUpload.words.length < 5) {
        actions.ui.showToast("Decks must contain at least 5 words to be uploaded.", true);
        return;
    }

    if (!supabaseUrl || !supabaseAnonKey) {
        actions.ui.showToast("Supabase credentials required for uploading.", true);
        return;
    }

    const confirmed = await actions.showConfirmation({
        title: `Upload "${deckToUpload.title}"?`,
        message: "This will make your deck available to all other WordWise users in the public library.",
        confirmText: "Upload",
        iconClass: "ph-fill ph-upload-simple"
    });
    if (!confirmed) return;

    const toastId = 'deck-upload';
    actions.ui.showToast("Uploading deck...", false, toastId, true);

    const sanitizedWords = deckToUpload.words.map(word => ({
        text: word.text,
        definitions: {
            flashcard: word.definitions.flashcard || null,
            detailed: word.definitions.detailed || null,
            gemini: word.definitions.gemini || null
        },
        imageUrl: word.isImageProvisional ? null : word.imageUrl,
        image_query: word.image_query || null,
        example: word.example || null,
        note: word.note || null,
        tags: word.tags || []
    }));

    const payload = {
        title: deckToUpload.title,
        description: deckToUpload.description,
        type: deckToUpload.type,
        image_url: deckToUpload.imageUrl,
        image_query: deckToUpload.image_query || null,
        word_count: sanitizedWords.length,
        words: sanitizedWords
    };

    const tableName = 'published_decks';
    const apiUrl = `${supabaseUrl}/rest/v1/${tableName}`;

    try {
        const response = await fetch(apiUrl, {
            method: 'POST',
            headers: {
                'apikey': supabaseAnonKey,
                'Authorization': `Bearer ${supabaseAnonKey}`,
                'Content-Type': 'application/json',
                'Prefer': 'return=minimal'
            },
            body: JSON.stringify(payload)
        });

        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(errorData.message || `HTTP error! status: ${response.status}`);
        }

        actions.ui.hideToast(toastId);
        actions.ui.showToast(`Deck "${deckToUpload.title}" uploaded successfully!`);

    } catch (error) {
        actions.ui.hideToast(toastId);
        actions.ui.showToast(`Upload failed: ${error.message}`, true);
    }
}

