// /settings.js
// Manages application settings, persistence, and UI synchronization.

export let automationSettings = {};
export let studySettings = {};
export let apiSettings = {};

let DOM = {};

export function initSettings(elements) {
    DOM = elements;
    loadAutomationSettings();
    loadStudySettings();
    loadApiSettings();
    console.log("Settings module initialized.");
}

// --- Automation Settings ---

function loadAutomationSettings() {
    const settingsJSON = localStorage.getItem('wordwiseAutomationSettings');
    const defaultSettings = {
        enableImageAutomation: true,
        enableAutoDefinitions: true,
        imageAutomationDeckTypes: { Vocabulary: true, Expressions: true, Subtitle: true, blacklist: [] },
        autoDefinitionsDeckTypes: { Vocabulary: true, Expressions: true, Subtitle: true, blacklist: [] }
    };
    automationSettings = settingsJSON ? { ...defaultSettings, ...JSON.parse(settingsJSON) } : defaultSettings;
}

export function saveAutomationSettings() {
    localStorage.setItem('wordwiseAutomationSettings', JSON.stringify(automationSettings));
}

export function syncAiAutomationModalUI() {
    if (!DOM.screens.aiAutomation) return;

    // Sync master toggles
    const imgToggle = DOM.screens.aiAutomation.querySelector('.master-automation-toggle[data-feature-key="enableImageAutomation"]');
    const defToggle = DOM.screens.aiAutomation.querySelector('.master-automation-toggle[data-feature-key="enableAutoDefinitions"]');
    if (imgToggle) imgToggle.checked = automationSettings.enableImageAutomation;
    if (defToggle) defToggle.checked = automationSettings.enableAutoDefinitions;

    // Sync deck type buttons for each feature
    const featureCards = DOM.screens.aiAutomation.querySelectorAll('.automation-card[data-feature-key]');
    featureCards.forEach(card => {
        const featureKey = card.dataset.featureKey;
        const typeSettings = automationSettings[featureKey];

        card.querySelectorAll('.deck-type-btn').forEach(btn => {
            const deckType = btn.dataset.type;
            btn.classList.toggle('active', typeSettings[deckType] === true);
        });
    });
}

// --- Study Settings ---

function loadStudySettings() {
    const settingsJSON = localStorage.getItem('wordwiseStudySettings');
    const defaultSettings = {
        prioritizeSrs: true,
        reverseFlashcards: false,
    };
    studySettings = { ...defaultSettings, ...(settingsJSON ? JSON.parse(settingsJSON) : {}) };

    // Sync UI toggles
    const srsToggle = document.getElementById('prioritize-srs-toggle');
    const reverseToggle = document.getElementById('reverse-flashcards-toggle');
    if (srsToggle) srsToggle.checked = studySettings.prioritizeSrs;
    if (reverseToggle) reverseToggle.checked = studySettings.reverseFlashcards;
}

export function saveStudySettings() {
    localStorage.setItem('wordwiseStudySettings', JSON.stringify(studySettings));
}

// --- API Settings ---

function loadApiSettings() {
    const settingsJSON = localStorage.getItem('wordwiseApiSettings');
    const defaultSettings = {
        groq: true,
        gemini: true,
        merriamWebster: true,
        publicDictionary: true,
        images: true
    };
