// State for Google Search Modal
let isCseScriptLoaded = false;

/**
 * Prompts the user for a new name for a deck.
 * @param {string} originalName - The current name.
 * @returns {Promise<string|null>} The new name or null if cancelled.
 */
export async function promptForNewName(originalName) {
    let newName = null;
    // We need to access decks to check for duplicates. 
    // In a pure UI module, we might usually ask the orchestrator, but for a prompt loop, accessing state is acceptable.
    const { decks } = getState(); 

    while (true) {
        const suggestedName = newName ? newName : `${originalName} (Copy)`;
        newName = prompt(`Please enter a new name for the deck:`, suggestedName);

        if (newName === null) return null; // Cancelled

        newName = newName.trim();
        if (newName === "") {
            alert("Deck name cannot be empty.");
            continue;
        }

        const isDuplicate = decks.some(d => d.title.toLowerCase() === newName.toLowerCase());
        if (isDuplicate) {
            alert(`A deck named "${newName}" already exists. Please choose a different name.`);
        } else {
            return newName;
        }
    }
}

/**
 * Opens the Google Custom Search Engine modal.
 * @param {string} searchTerm - The term to search for.
 */
export async function openGoogleSearchModal(searchTerm) {
    if (!DOM.screens.googleSearch) {
        DOM.screens.googleSearch = document.getElementById('google-search-modal');
    }

    showModal(DOM.screens.googleSearch);
    const contentArea = document.getElementById('google-search-content');
    const modalTitle = document.getElementById('google-search-modal-title');
    modalTitle.textContent = `Search for "${searchTerm}"`;

    contentArea.innerHTML = '<div class="no-results-message" style="padding-top: 3rem;">Loading Google Search...</div>';

    const { supabaseUrl, supabaseAnonKey } = getState();

    try {
        // Dynamic import for Supabase client if not globally available, 
        // but typically we rely on the global script or passed actions. 
        // For this UI component, we'll try to fetch the CX ID directly via the app's proxy or passed callback if possible.
        // However, the original code imported the client. We will assume the Supabase client library is available via CDN in index.html.
        const { createClient } = await import('https://esm.sh/@supabase/supabase-js@2');
        const supabase = createClient(supabaseUrl, supabaseAnonKey);

        const { data, error } = await supabase.from('api_keys').select('api_key').eq('service', 'google-cse').eq('name', 'CX_ID');
        if (error) throw new Error(`Supabase error: ${error.message}`);
        if (!data || data.length === 0) throw new Error("CX_ID not found in Supabase api_keys table.");

        const cxKey = data[0].api_key;
        const finalQuery = `definition of ${searchTerm}`;

        contentArea.innerHTML = '<div class="gcse-search" data-gname="wordwise-search"></div>';

        function tryExecuteSearch() {
            if (window.google && google.search && google.search.cse && google.search.cse.element) {
                const cseElement = google.search.cse.element.getElement('wordwise-search');
                if (cseElement) {
                    cseElement.prefillQuery(finalQuery);
                    cseElement.execute(finalQuery);
                } else {
                    setTimeout(tryExecuteSearch, 250);
                }
            } else {
                setTimeout(tryExecuteSearch, 250);
            }
        }

        if (!isCseScriptLoaded) {
            const script = document.createElement('script');
            script.src = `https://cse.google.com/cse.js?cx=${cxKey}`;
            script.async = true;
            script.onload = () => {
                isCseScriptLoaded = true;
                tryExecuteSearch();
            };
            document.body.appendChild(script);
        } else {
            google.search.cse.element.render({ div: contentArea.querySelector('.gcse-search'), tag: 'search' });
            tryExecuteSearch();
        }
    } catch (error) {
        console.error("Failed to load Google Search:", error);
        contentArea.innerHTML = `<div class="no-results-message" style="padding: 3rem;">
            <p style="font-weight: 600;">Could not load Google Search</p>
            <p>${error.message}</p>
        </div>`;
    }
}

/**
 * Toggles the favorite status of a word across all decks.
 * @param {string} deckId - The ID of the deck where the click originated.
 * @param {string} wordText - The text of the word to toggle.
 */
export function handleToggleFavorite(deckId, wordText) {
    const FAVORITES_DECK_ID = 'favorites_deck';
    const { decks } = getState();

    const clickedDeck = decks.find(d => d.id === deckId);
    if (!clickedDeck) return;
    const clickedWord = clickedDeck.words.find(w => w.text === wordText);
    if (!clickedWord) return;

    const newFavoriteStatus = !clickedWord.isFavorite;

    // Synchronize status across ALL instances
    decks.forEach(deck => {
        deck.words.forEach(word => {
            if (word.text.toLowerCase() === wordText.toLowerCase()) {
                word.isFavorite = newFavoriteStatus;
            }
        });
    });

    // Find or create Favorites deck
    let favoritesDeck = decks.find(d => d.id === FAVORITES_DECK_ID);
    if (newFavoriteStatus && !favoritesDeck) {
        favoritesDeck = {
            id: FAVORITES_DECK_ID,
            title: "Favorites",
            description: "A collection of your favorite words and expressions.",
            words: [],
            type: null,
            isSpecial: false,
            imageUrl: 'https://previews.123rf.com/images/faysalfarhan/faysalfarhan1504/faysalfarhan150400087/38176968-favorite-star-icon-yellow-square-button.jpg',
            createdAt: new Date().toISOString()
        };
        decks.unshift(favoritesDeck);
    }

    // Add/Remove from Favorites deck
    if (favoritesDeck) {
        const wordIndexInFavorites = favoritesDeck.words.findIndex(w => w.text.toLowerCase() === wordText.toLowerCase());

        if (newFavoriteStatus) {
            if (wordIndexInFavorites === -1) {
                const wordCopy = JSON.parse(JSON.stringify(clickedWord));
                wordCopy.originType = clickedDeck.type; 
                favoritesDeck.words.push(wordCopy);
                actions.ui.showToast(`Added "${wordText}" to Favorites.`);
            }
        } else {
            if (wordIndexInFavorites > -1) {
                favoritesDeck.words.splice(wordIndexInFavorites, 1);
                actions.ui.showToast(`Removed "${wordText}" from Favorites.`);
                if (favoritesDeck.words.length === 0) {
                    // Remove empty favorites deck from the main list
                    const idx = decks.indexOf(favoritesDeck);
                    if (idx > -1) decks.splice(idx, 1);
                }

                // Refresh viewer if currently viewing Favorites
                // Note: actions.onGetCurrentDeck must be mapped to deckViewer.getCurrentDeck in app.js
                const currentlyViewedDeck = actions.onGetCurrentDeck(); 
                if (currentlyViewedDeck && currentlyViewedDeck.id === FAVORITES_DECK_ID) {
                    // If we just deleted the deck, we can't reopen it. Check if it still exists.
                    if (decks.includes(favoritesDeck)) {
                         actions.onOpenDeck(favoritesDeck);
                    } else {
                        // If deck is gone, we should probably close the viewer, but for now let's just leave it.
                        // Or refresh with empty state.
                        actions.onOpenDeck({ ...favoritesDeck, words: [] });
                    }
                }
            }
        }
    }

    // Save and update UI
    actions.onSaveDecks();

    // Update icons in DOM manually for immediate feedback
    const allFavoriteButtons = document.querySelectorAll(`.favorite-toggle-btn[data-word-text="${wordText}"]`);
    allFavoriteButtons.forEach(btn => {
        const icon = btn.querySelector('i');
        if (icon) {
            icon.className = newFavoriteStatus ? 'ph-fill ph-star' : 'ph ph-star';
        }
    });

    renderDeckScreen(); // Refresh counts
}

/**
 * Runs the background process to improve word images using AI.
 * This iterates through decks and finds words marked as 'provisional'.
 * @param {object} callbacks - Callbacks for UI updates { refreshHome, refreshDeckViewer, getCurrentHomeWord, getCurrentViewerWord, getCurrentDeck }
 */
export async function runImageRefinementProcess(callbacks) {
    const { automationSettings } = getState();

    if (!automationSettings.enableImageAutomation) {
        console.log("⚙️ [BG Refiner] Disabled via settings. Worker is idle.");
        return;
    }
    if (!navigator.onLine) {
        console.log("⚙️ [BG Refiner] Offline. Skipping image refinement process.");
        return;
    }

    console.log("⚙️ [BG Refiner] Starting background image refinement process...");
    const { decks } = getState();
    const wordsToRefine = [];

    decks.forEach(deck => {
        // Skip special/blacklisted decks
        if (deck.isSpecial || automationSettings.imageAutomationDeckTypes.blacklist.includes(deck.id)) return;

        const deckType = deck.type || 'Vocabulary';
        if (automationSettings.imageAutomationDeckTypes[deckType] === false) return;

        deck.words.forEach(word => {
            if (word.isImageProvisional === true) {
                wordsToRefine.push({ ...word, deckId: deck.id });
            }
        });
    });

    if (wordsToRefine.length === 0) {
        console.log("⚙️ [BG Refiner] No provisional images found. Worker is idle.");
        return;
    }

    console.log(`⚙️ [BG Refiner] Found ${wordsToRefine.length} images in the queue.`);
    const REFINEMENT_LIMIT_PER_SESSION = 25;
    let refinedInThisSession = 0;

    try {
        for (const wordWithContext of wordsToRefine) {
            if (refinedInThisSession >= REFINEMENT_LIMIT_PER_SESSION) {
                console.log(`🏁 [BG Refiner] Session limit reached.`);
                utils.showToast(`AI refined ${refinedInThisSession} images. More next time.`); // Assuming utils passed in init has showToast, or actions
                return;
            }

            const deck = decks.find(d => d.id === wordWithContext.deckId);
            if (!deck) continue;

            // Re-check settings (in case they changed during loop)
            const deckType = deck.type || 'Vocabulary';
            if (automationSettings.imageAutomationDeckTypes[deckType] === false) continue;
            if (automationSettings.imageAutomationDeckTypes.blacklist.includes(deck.id)) continue;

            const word = deck.words.find(w => w.text === wordWithContext.text);
            if (!word) continue;

            const result = await getBestImageUsingAI(word, deck);

            if (result === null) {
                console.log(`🤷 [BG Refiner] AI rejected images for "${word.text}".`);
                word.isImageProvisional = false;
                actions.saveDecks();
            } else if (result && result.imageUrl) {
                console.log(`✅ [BG Refiner] Upgraded image for "${word.text}".`);
                word.imageUrl = result.imageUrl;
                word.image_query = result.query;
                word.isImageProvisional = false;
                actions.saveDecks();

                // Live UI Refresh
                const homeWord = callbacks.getCurrentHomeWord();
                if (homeWord && homeWord.text === word.text) {
                    callbacks.refreshHome();
                }

                const viewerWord = callbacks.getCurrentViewerWord();
                if (viewerWord && viewerWord.text === word.text) {
                    const currentDeck = callbacks.getCurrentDeck();
                    if (currentDeck) callbacks.refreshDeckViewer(currentDeck, viewerWord.text);
                }
            } 

            refinedInThisSession++;
            if (refinedInThisSession < wordsToRefine.length && refinedInThisSession < REFINEMENT_LIMIT_PER_SESSION) {
                await new Promise(resolve => setTimeout(resolve, 10000)); // 10s delay
            }
        }
    } catch (error) {
        console.error("💥 [BG Refiner] Process stopped:", error);
    }
}

