                    text = "💠"
                    textSize = 18f
                    setPadding(0, 0, 30, 0)
                }
                val info = LinearLayout(ctx).apply {
                    orientation = LinearLayout.VERTICAL
                    addView(TextView(ctx).apply {
                        text = s.name
                        textSize = 14f
                        setTextColor(Color.WHITE)
                        typeface = Typeface.DEFAULT_BOLD
                    })
