        // THE FIX: Centralize the visibility logic here
        if (showPagination && totalPages > 1) {
            paginationControls.classList.add('visible');
            const start = (imageSearchCurrentPage - 1) * IMAGES_PER_PAGE;
            const end = start + IMAGES_PER_PAGE;
