}

export async function handleImageSelectionConfirm() {
    if (!selectedImageUrl) return;
    const { type, id, wordText } = imageSearchContext;
    let finalUrl = selectedImageUrl;
    const lastQuery = document.getElementById('image-search-input').value.trim();

    if (type === 'movie_poster') {
        const toastId = 'poster-upload';
        ui.showToast("Uploading poster to your library...", false, toastId, true);
        try {
            const result = await api.callSupabaseFunction('image-proxy-uploader', {
                imageUrl: selectedImageUrl,
                bucketName: 'movie_posters'
            });
            if (result.error) throw new Error(result.error);
            finalUrl = result.publicUrl;
            ui.hideToast(toastId);
        } catch (error) {
            ui.hideToast(toastId);
            ui.showToast(`Poster upload failed: ${error.message}`, true);
            return;
        }
    }

    const { decks, movies } = getState();

    if (type === 'deck') {
        const deck = decks.find(d => d.id === id);
        if (deck) {
            deck.imageUrl = finalUrl;
            deck.image_query = lastQuery;
        }
    } else if (type === 'word') {
        const deck = decks.find(d => d.id === id);
        const word = deck?.words.find(w => w.text === wordText);
        if (word) {
            word.imageUrl = finalUrl;
            word.image_query = lastQuery;
            word.isImageProvisional = false;
        }
    } else if (type === 'movie_poster_update') {
        const movieToUpdate = movies.find(m => m.id === id);
        if (movieToUpdate) {
            movieToUpdate.poster = finalUrl;
            movieToUpdate.image_query = lastQuery;
            localStorage.setItem('wordwiseMovies', JSON.stringify(movies));
            // Refresh views via callbacks (or directly if allowed, but callbacks better)
            // actions.refreshMovieViews(id); 
            // Assuming movies are passed by reference in getState, modifying them here works,
            // but we need to trigger re-renders.
            actions.refreshMovies(); // We will pass movie.renderMoviesList here
        }
    }

    actions.saveDecks();
    actions.renderDeckScreen();

    if (type === 'movie_poster') {
        ui.showModal(DOM.screens.addMovie);
    } else {
        ui.closeAllModals(true);
    }

    if (type === 'word') {
        const deck = decks.find(d => d.id === id);
        actions.openDeck(deck, wordText);
    }
}

