operations.content:
// /interaction.js
// Handles complex user interactions: Long-press gestures and Selection Mode logic.

let pressTimer = null;
let longPressJustFinished = false;
let isSelectionMode = { decks: false, history: false, wotd: false };
let selectedIds = { decks: new Set(), history: new Set(), wotd: new Set() };

let DOM = {};
let actions = {};
let getState = () => ({});

export function initInteraction(config) {
    DOM = config.elements;
    actions = config.actions;
    getState = config.getState;
    setupInteractionListeners();
    console.log("Interaction module initialized.");
}

// --- Getters for external use ---
export function isLongPressJustFinished() {
    return longPressJustFinished;
}

export function resetLongPressFlag() {
    longPressJustFinished = false;
}

export function getSelectionModeState() {
    return isSelectionMode;
}

// --- Selection Mode Logic ---

export function enterSelectionMode(type, initialElement) {
    isSelectionMode[type] = true;
    const screenElement = type === 'decks' ? DOM.screens.decks : (type === 'history' ? DOM.screens.quizHistory : DOM.screens.wotdLog);
    const barPrefix = type === 'decks' ? 'deck' : type;
    const deleteBar = document.getElementById(`${barPrefix}-selection-delete-bar`);

    if (screenElement) screenElement.classList.add('selection-mode');
    if (deleteBar) deleteBar.classList.add('visible');

    toggleSelection(type, initialElement);
}

export function exitSelectionMode(type) {
    if (!isSelectionMode[type]) return;
    isSelectionMode[type] = false;
    selectedIds[type].clear();

    const screenElement = type === 'decks' ? DOM.screens.decks : (type === 'history' ? DOM.screens.quizHistory : DOM.screens.wotdLog);
    const barPrefix = type === 'decks' ? 'deck' : type;
    const deleteBar = document.getElementById(`${barPrefix}-selection-delete-bar`);

    if (screenElement) screenElement.classList.remove('selection-mode');
    if (deleteBar) deleteBar.classList.remove('visible');

    const itemSelector = type === 'decks' ? '.grid-deck-card, .deck-list-card' : (type === 'history' ? '.history-quiz-item' : '.wotd-log-entry');
    document.querySelectorAll(`${itemSelector}.selected`).forEach(el => {
        el.classList.remove('selected');
    });
}

export function toggleSelection(type, itemElement) {
    if (!itemElement) return;

    const idAttribute = type === 'decks' ? 'data-deck-id' : (type === 'history' ? 'data-quiz-id' : 'data-wotd-id');
    const id = itemElement.getAttribute(idAttribute);
    if (!id) return;

    if (selectedIds[type].has(id)) {
        selectedIds[type].delete(id);
        itemElement.classList.remove('selected');
    } else {
        selectedIds[type].add(id);
        itemElement.classList.add('selected');
    }

    updateSelectionBar(type);
}

function updateSelectionBar(type) {
    const count = selectedIds[type].size;
    const { decks } = getState();

    if (count === 0) {
        exitSelectionMode(type);
        return;
    }

    if (type === 'decks') {
        document.getElementById('deck-selection-move-count').textContent = `Move ${count}`;
        document.getElementById('deck-selection-count').textContent = `Delete ${count}`;

        // Pin button logic
        const pinBtnText = document.getElementById('deck-selection-pin-text');
        const pinBtnIcon = document.getElementById('deck-selection-pin-btn').querySelector('i');
        const selectedDecks = Array.from(selectedIds.decks).map(id => decks.find(d => d.id === id));
        const shouldPin = selectedDecks.some(deck => deck && !deck.isPinned);

        if (shouldPin) {
            pinBtnText.textContent = `Pin ${count}`;
            pinBtnIcon.className = 'ph ph-push-pin';
        } else {
            pinBtnText.textContent = `Unpin ${count}`;
            pinBtnIcon.className = 'ph ph-push-pin-slash';
        }

        // Single-action buttons logic
        const singleActionDivider = document.getElementById('deck-selection-single-action-divider');
        const testBtn = document.getElementById('deck-selection-test-btn');
        const editBtn = document.getElementById('deck-selection-edit-btn');
        const uploadBtn = document.getElementById('deck-selection-upload-btn');
        const logBtn = document.getElementById('deck-selection-log-btn');

        if (count === 1) {
            const [deckId] = selectedIds.decks;
            const deck = decks.find(d => d.id === deckId);

            singleActionDivider.style.display = 'block';
            testBtn.style.display = 'flex';

            if (deck && deck.isSpecial) {
                logBtn.style.display = 'flex';
                editBtn.style.display = 'none';
                uploadBtn.style.display = 'none';
            } else {
                editBtn.style.display = 'flex';
                uploadBtn.style.display = 'flex';
                logBtn.style.display = 'none';
            }
        } else {
            singleActionDivider.style.display = 'none';
            testBtn.style.display = 'none';
            editBtn.style.display = 'none';
            uploadBtn.style.display = 'none';
            logBtn.style.display = 'none';
        }

    } else if (type === 'history') {
        const countSpan = document.getElementById('history-selection-count');
        countSpan.textContent = `Delete ${count} Item${count > 1 ? 's' : ''}`;
    } else if (type === 'wotd') {
        const countSpan = document.getElementById('wotd-selection-count');
        countSpan.textContent = `Delete ${count} Item${count > 1 ? 's' : ''}`;
    }
}

// --- Helper Actions used by Selection Bar ---

async function handleDeckSelectionAction(action, targetId = null) {
    // Need access to main state to modify decks
    const state = getState();
    let decks = state.decks;

    if (action === 'cancel') {
        exitSelectionMode('decks');
        return;
    }

    if (action === 'pin') {
        const selectedDecks = Array.from(selectedIds.decks).map(id => decks.find(d => d.id === id));
        const shouldPin = selectedDecks.some(deck => deck && !deck.isPinned);
        let count = 0;
        decks.forEach(deck => {
            if (selectedIds.decks.has(deck.id)) {
                deck.isPinned = shouldPin;
                if(shouldPin) count++;
            }
        });
        actions.saveDecks();
        actions.renderDeckScreen();
        exitSelectionMode('decks');
        actions.showToast(`${count} deck(s) ${shouldPin ? 'pinned' : 'unpinned'}.`);
    } 
    else if (action === 'delete') {
        const selectedDecks = Array.from(selectedIds.decks).map(id => decks.find(d => d.id === id));
        const deletableDecks = selectedDecks.filter(deck => deck && !deck.isSpecial);
        const specialDecks = selectedDecks.filter(deck => deck && deck.isSpecial);

        if (specialDecks.length > 0) {
            actions.showToast("Special system decks cannot be deleted.", true);
        }

        if (deletableDecks.length > 0) {
            const confirmed = await actions.showConfirmation({
                title: `Delete ${deletableDecks.length} Deck(s)?`,
                message: "This action is permanent and cannot be undone.",
                confirmText: "Delete",
                confirmStyle: "danger",
                iconClass: "ph-fill ph-trash"
            });
            if (confirmed) {
                // Perform deletion by updating the shared state via the provided callback or direct mutation if allowed
                // Ideally call a method on deckManager, but for batch delete we might need app.js coordination
                // For now, we will use the 'deleteDeck' action passed from app.js repeatedly or we need a batch delete action
                // Let's modify the 'decks' array in place since we got it from getState (assuming reference)
                // A cleaner way is to ask app.js to delete a list of IDs.
                actions.deleteDecksBatch(deletableDecks.map(d => d.id));
            }
        }
        exitSelectionMode('decks');
    }
    else if (action === 'move') {
        // Delegate to DeckManager logic exposed via actions
        actions.openMoveToFolderModal(selectedIds.decks); // We need to update this function to accept IDs
    }
    else if (action === 'test' || action === 'edit' || action === 'upload' || action === 'log') {
        // Single item actions
        const [deckId] = selectedIds.decks;
        const deck = decks.find(d => d.id === deckId);
        if(deck) {
            if (action === 'test') actions.openTestModal(deck);
            else if (action === 'edit') actions.handleEditDeck(deck);
            else if (action === 'upload') actions.handleUploadDeck(deck.id);
            else if (action === 'log') actions.openWotdLog(deck);
        }
        exitSelectionMode('decks');
    }
}

// --- Listeners ---

function setupInteractionListeners() {
    // --- Touch / Long Press Logic ---
    document.body.addEventListener('touchstart', (e) => {
        const targetDeck = e.target.closest('.grid-deck-card, .deck-list-card');
        const targetHistoryItem = e.target.closest('.history-quiz-item');
        const targetWotdItem = e.target.closest('.wotd-log-entry');
        const targetItem = targetDeck || targetHistoryItem || targetWotdItem;

        if (targetItem && !isSelectionMode.decks && !isSelectionMode.history && !isSelectionMode.wotd) {
            pressTimer = setTimeout(() => {
                e.preventDefault();
                if (navigator.vibrate) navigator.vibrate(50);

                longPressJustFinished = true;

                if (targetDeck) enterSelectionMode('decks', targetDeck);
                else if (targetHistoryItem) enterSelectionMode('history', targetHistoryItem);
                else if (targetWotdItem) enterSelectionMode('wotd', targetWotdItem);

                pressTimer = null;
            }, 600);
        }
    }, { passive: false });

    document.body.addEventListener('touchend', () => {
        if (pressTimer) clearTimeout(pressTimer);
        setTimeout(() => { longPressJustFinished = false; }, 0);
    });

    document.body.addEventListener('touchmove', () => { if (pressTimer) clearTimeout(pressTimer); });
    document.body.addEventListener('touchcancel', () => { if (pressTimer) clearTimeout(pressTimer); });

    // --- Selection Bar Click Listeners ---

    // Decks Selection Bar
    const deckBar = document.getElementById('deck-selection-delete-bar');
    if (deckBar) {
        deckBar.addEventListener('click', async (e) => {
            if (e.target.closest('.cancel-selection-btn')) handleDeckSelectionAction('cancel');
            else if (e.target.closest('#deck-selection-pin-btn')) handleDeckSelectionAction('pin');
            else if (e.target.closest('#deck-selection-delete-btn')) handleDeckSelectionAction('delete');
            else if (e.target.closest('#deck-selection-move-btn')) handleDeckSelectionAction('move');
            else if (e.target.closest('#deck-selection-test-btn')) handleDeckSelectionAction('test');
            else if (e.target.closest('#deck-selection-edit-btn')) handleDeckSelectionAction('edit');
            else if (e.target.closest('#deck-selection-upload-btn')) handleDeckSelectionAction('upload');
            else if (e.target.closest('#deck-selection-log-btn')) handleDeckSelectionAction('log');
        });
    }

    // History Selection Bar
    const historyBar = document.getElementById('history-selection-delete-bar');
    if (historyBar) {
        historyBar.addEventListener('click', async (e) => {
            if (e.target.closest('.cancel-selection-btn')) {
                exitSelectionMode('history');
                return;
            }
            const idsToDelete = Array.from(selectedIds.history);
            if (idsToDelete.length > 0) {
                const confirmed = await actions.showConfirmation({
                    title: `Delete ${idsToDelete.length} History Item(s)?`,
                    message: "This will permanently remove the selected quiz records.",
                    confirmText: "Delete",
                    confirmStyle: "danger",
                    iconClass: "ph-fill ph-trash"
                });
                if (confirmed) {
                    actions.deleteQuizHistory(idsToDelete);
                }
            }
            exitSelectionMode('history');
        });
    }

    // WotD Selection Bar
    const wotdBar = document.getElementById('wotd-selection-delete-bar');
    if (wotdBar) {
        wotdBar.addEventListener('click', async (e) => {
            if (e.target.closest('.cancel-selection-btn')) {
                exitSelectionMode('wotd');
                return;
            }
            const idsToDelete = Array.from(selectedIds.wotd);
            if (idsToDelete.length > 0) {
                const confirmed = await actions.showConfirmation({
                    title: `Delete ${idsToDelete.length} Log Item(s)?`,
                    message: "This will permanently remove the selected words from the log.",
                    confirmText: "Delete",
                    confirmStyle: "danger",
                    iconClass: "ph-fill ph-trash"
                });
                if (confirmed) {
                    actions.deleteWotdLogItems(idsToDelete);
                }
            }
            exitSelectionMode('wotd');
        });
    }

    // Global Click to Exit Selection
    document.addEventListener('click', (e) => {
        if (isSelectionMode.decks && 
            !e.target.closest('.grid-deck-card, .deck-list-card') && 
            !e.target.closest('#deck-selection-delete-bar') && 
            !e.target.closest('#move-to-folder-modal')) {
            exitSelectionMode('decks');
        }
        if (isSelectionMode.history && !e.target.closest('.history-quiz-item') && !e.target.closest('#history-selection-delete-bar')) {
            exitSelectionMode('history');
        }
        if (isSelectionMode.wotd && !e.target.closest('.wotd-log-entry') && !e.target.closest('#wotd-selection-delete-bar')) {
            exitSelectionMode('wotd');
        }
    });
}

