operations.content:
interaction.initInteraction({
    elements: DOM,
    getState: () => ({ decks }),
    actions: {
        showToast: ui.showToast,
        showConfirmation: ui.showConfirmationDialog,
        saveDecks: saveDecksToStorage,
        renderDeckScreen: deckManager.renderDeckScreen,
        handleEditDeck: deckManager.handleEditDeck,
        handleUploadDeck: handleUploadDeck,
        deleteDecksBatch: (idsToDelete) => {
            // Batch delete implementation
            const idsSet = new Set(idsToDelete);
            decks = decks.filter(d => !idsSet.has(d.id));
            saveDecksToStorage();
            deckManager.renderDeckScreen();
        },
        openMoveToFolderModal: (selectedIdsSet) => {
            // Pass the set to the modal opener if needed, or set global state for it
            // For now, deckManager accesses a global 'currentMoveTargetFolderId' but it needs the source IDs
            // Let's modify deckManager to accept source IDs or use the interaction module's state
            deckManager.openMoveToFolderModal(selectedIdsSet);
        },
        openTestModal: (deck) => {
            quiz.setQuizDeckId(deck.id);
            document.getElementById('test-type-deck-title').textContent = `Test '${deck.title}'`;
            ui.showModal(DOM.screens.testType);
        },
        openWotdLog: (deck) => {
            ui.renderWotdLog(deck);
            ui.showModal(DOM.screens.wotdLog);
        },
        deleteQuizHistory: (ids) => {
            quiz.deleteQuizFromHistory(ids);
        },
        deleteWotdLogItems: (ids) => {
            const wotdDeck = decks.find(d => d.isSpecial);
            if(wotdDeck) {
                const idsSet = new Set(ids);
                wotdDeck.words = wotdDeck.words.filter(word => !idsSet.has(word.text));
                saveDecksToStorage();
                ui.renderWotdLog(wotdDeck); 
            }
        }
    }
});

