// --- State for Gestures ---
let aboutTapCount = 0;
let aboutTapTimer = null;
let settingsTapCount = 0;
let settingsTapTimer = null;
let isErudaActive = false;

export function applySavedTheme() {
    const savedTheme = localStorage.getItem('wordwiseTheme');
    const themeIcon = document.getElementById('theme-icon');
    if (savedTheme === 'dark') {
        document.documentElement.classList.add('dark-theme');
        if (themeIcon) themeIcon.className = 'ph ph-sun';
    } else {
        document.documentElement.classList.remove('dark-theme');
        if (themeIcon) themeIcon.className = 'ph ph-moon';
    }
}

export function setupSettingsListeners() {
    // Theme Toggle
    const themeBtn = document.getElementById('theme-toggle-btn');
    if (themeBtn) {
        themeBtn.addEventListener('click', () => {
            const html = document.documentElement;
            html.classList.toggle('dark-theme');
            const isDark = html.classList.contains('dark-theme');
            localStorage.setItem('wordwiseTheme', isDark ? 'dark' : 'light');
            applySavedTheme();
        });
    }

    // Eruda (Developer Console) Toggle - Triple tap on About
    const aboutBtn = document.getElementById('about-btn');
    if (aboutBtn) {
        aboutBtn.addEventListener('click', () => {
            aboutTapCount++;
            if (aboutTapTimer) clearTimeout(aboutTapTimer);

            if (aboutTapCount === 3) {
                if (typeof eruda !== 'undefined') {
                    if (!isErudaActive) {
                        console.log("Developer mode activated. Initializing Eruda console.");
                        eruda.init();
                        isErudaActive = true;
                        localStorage.setItem('wordwiseErudaActive', 'true');
                    } else {
                        console.log("Developer mode deactivated. Destroying Eruda console.");
                        eruda.destroy();
                        isErudaActive = false;
                        localStorage.setItem('wordwiseErudaActive', 'false');
                    }
                } else {
                    alert("Eruda library not found.");
                }
                aboutTapCount = 0;
            } else {
                aboutTapTimer = setTimeout(() => { aboutTapCount = 0; }, 600);
            }
        });
    }

    // Backend Settings Toggle - Triple tap on Settings Tab (handled via return value or direct DOM attachment)
    // Since Navigation is in app.js, we might export a helper or attach it here if we can access the nav link.
    // But DOM.navLinks might not be passed fully structure. 
    // Let's attach a specific listener to the backend settings wrapper logic if possible, 
    // or handle it in the handleSettingsTabClick exported below.
}

export function handleSettingsTabClick() {
    // Triple-tap logic to toggle backend settings visibility
    settingsTapCount++;
    if (settingsTapTimer) clearTimeout(settingsTapTimer);
    if (settingsTapCount === 3) {
        const wrapper = document.getElementById('backend-settings-wrapper');
        if (wrapper) {
            const isVisible = wrapper.classList.toggle('visible');
            localStorage.setItem('wordwiseBackendSettingsVisible', isVisible);
        }
        settingsTapCount = 0;
    } else {
        settingsTapTimer = setTimeout(() => {
            settingsTapCount = 0;
        }, 600);
    }
}

export function checkPersistentSettings() {
    // Eruda
    if (localStorage.getItem('wordwiseErudaActive') === 'true' && typeof eruda !== 'undefined') {
        eruda.init();
        isErudaActive = true;
    }
    // Backend Settings
    if (localStorage.getItem('wordwiseBackendSettingsVisible') === 'true') {
        const wrapper = document.getElementById('backend-settings-wrapper');
        if (wrapper) wrapper.classList.add('visible');
    }
}

