export function setupGlobalUIListeners() {
    // Sidebar Toggling
    const toggleSidebar = () => {
        if (DOM.deckSidebar) DOM.deckSidebar.classList.toggle('open');
        if (DOM.deckSidebarOverlay) DOM.deckSidebarOverlay.classList.toggle('open');
    };
    const sbBtn = document.getElementById('sidebar-toggle-btn');
    if (sbBtn) sbBtn.addEventListener('click', toggleSidebar);
    if (DOM.deckSidebarOverlay) DOM.deckSidebarOverlay.addEventListener('click', toggleSidebar);

    // Global Click Handler (Menus, Search collapsing)
    document.addEventListener('click', (e) => {
        // Close active pop-up menus
        if (!e.target.closest('.options-container') && !e.target.closest('.popover-toggle')) {
            closeActiveMenu();
        }

        // Close active sliding submenus
        else if (!e.target.closest('.flashcard-option-parent')) {
            const activeSubmenu = document.querySelector('.flashcard-option-parent.submenu-active');
            if (activeSubmenu) {
                activeSubmenu.classList.remove('submenu-active');
            }
        }

        // Collapse active header search bars
        const decksHeader = document.getElementById('decks-header');
        const moviesHeader = document.getElementById('movie-list-header');
        const exploreHeader = document.getElementById('explore-header'); 

        if (decksHeader && decksHeader.classList.contains('search-active') && !e.target.closest('#decks-header')) {
            decksHeader.classList.remove('search-active');
        }
        if (moviesHeader && moviesHeader.classList.contains('search-active') && !e.target.closest('#movie-list-header')) {
            moviesHeader.classList.remove('search-active');
        }
        if (exploreHeader && exploreHeader.classList.contains('search-active') && !e.target.closest('#explore-header')) {
            exploreHeader.classList.remove('search-active');
        }

        // Generic Modal Close Button Logic
        const genericCloseBtn = e.target.closest('.close-modal-btn');
        if (genericCloseBtn) {
            // Exceptions handled by specific modules
            if (genericCloseBtn.closest('#confirm-action-modal')) return;
            if (genericCloseBtn.closest('#edit-movie-modal')) return;
            if (genericCloseBtn.closest('#rename-titles-modal')) return;

            e.preventDefault();
            closeAllModals(true);
        }
    });

    // Section Toggles (Danger Zone, etc.)
    const setupToggle = (btnId, containerId) => {
        const btn = document.getElementById(btnId);
        const container = document.getElementById(containerId);
        if (btn && container) {
            btn.addEventListener('click', () => {
                const icon = btn.querySelector('.ph-caret-right');
                const isVisible = container.style.display === 'block';
                if (isVisible) {
                    container.style.maxHeight = '0px';
                    setTimeout(() => container.style.display = 'none', 400);
                } else {
                    container.style.display = 'block';
                    setTimeout(() => container.style.maxHeight = '500px', 10);
                }
                if (icon) icon.style.transform = isVisible ? 'rotate(0deg)' : 'rotate(90deg)';
            });
        }
    };

    setupToggle('danger-zone-toggle', 'danger-zone-container');
    setupToggle('supabase-keys-toggle', 'supabase-keys-container');
}

