export function getSelectedIds() {
    return selectedIds;
}

// --- Folder Move Logic ---
let currentMoveTargetFolderId = null;

export function renderMoveToFolderList(parentId = null) {
    const { folders } = getState();
    const listEl = document.getElementById('move-to-folder-list');
    const headerTitleEl = document.getElementById('move-to-folder-header-title');
    const backBtn = document.getElementById('move-to-folder-back-btn');
    listEl.innerHTML = '';

    const getPath = (fid) => {
        if (!fid) return "Move to...";
        let path = [];
        let curr = folders.find(f => f.id === fid);
        while (curr) { path.unshift(curr.name); curr = folders.find(f => f.id === curr.parentId); }
        return `Move to... / ${path.join(' / ')}`;
    };

    headerTitleEl.textContent = getPath(parentId);
    if (parentId) {
        const parent = folders.find(f => f.id === parentId);
        backBtn.dataset.parentId = parent?.parentId || 'null';
        backBtn.style.visibility = 'visible';
    } else { backBtn.style.visibility = 'hidden'; }

    if (parentId === null) {
        listEl.innerHTML += `<div class="list-option" data-folder-id="null"><div class="list-option-main"><div class="list-option-icon-wrapper"><i class="ph ph-files"></i></div><p class="list-option-text">Top Level</p></div></div>`;
    }

    folders.filter(f => f.parentId === parentId).forEach(folder => {
        const hasChildren = folders.some(f => f.parentId === folder.id);
        const selected = currentMoveTargetFolderId === folder.id ? 'selected' : '';
        listEl.innerHTML += `<div class="list-option ${selected}" data-folder-id="${folder.id}"><div class="list-option-main"><div class="list-option-icon-wrapper"><i class="ph-fill ph-folder" style="color: ${folder.color};"></i></div><p class="list-option-text">${folder.name}</p></div>${hasChildren ? `<button class="drill-down-btn" data-folder-id="${folder.id}"><i class="ph ph-caret-right"></i></button>` : ''}</div>`;
    });
}

export function openMoveToFolderModal() {
    currentMoveTargetFolderId = null;
    renderMoveToFolderList(null);
    actions.ui.showModal(document.getElementById('move-to-folder-modal'));
}

export function handleFolderSelectionClick(e) {
    const drillDownBtn = e.target.closest('.drill-down-btn');
    const folderOption = e.target.closest('.list-option');
    const backBtn = e.target.closest('#move-to-folder-back-btn');

    if (drillDownBtn) {
        e.stopPropagation();
        renderMoveToFolderList(drillDownBtn.dataset.folderId);
    } else if (folderOption) {
        document.querySelectorAll('#move-to-folder-list .list-option').forEach(opt => opt.classList.remove('selected'));
        folderOption.classList.add('selected');
        currentMoveTargetFolderId = folderOption.dataset.folderId;
        document.getElementById('confirm-move-btn').disabled = false;
    } else if (backBtn) {
        const parentId = backBtn.dataset.parentId === 'null' ? null : backBtn.dataset.parentId;
        renderMoveToFolderList(parentId);
    }
}

export function handleMoveSelectedDecks(selectedIdsSet) {
    const { decks } = getState();
    const folderId = currentMoveTargetFolderId === 'null' ? null : currentMoveTargetFolderId;

    selectedIdsSet.forEach(id => { 
        const d = decks.find(deck => deck.id === id); 
        if(d) d.folderId = folderId; 
    });

    actions.onSaveDecks();
    renderDeckScreen();
    actions.ui.closeAllModals();
    // We need to exit selection mode via the interaction module, but we don't have direct access here.
    // We will assume app.js handles the exit or we dispatch an event.
    // Ideally actions.exitSelectionMode('decks');
    actions.ui.showToast("Decks moved.");
}

