            console.log(`✅ [AI Image Search] AI selected an image for query "${query}".`);
            return chosenUrl.trim();
        } else {
            console.log(`🤷 [AI Image Search] AI rejected all images for "${query}".`);
            return null;
        }
    } catch (error) {
        if (error.message.includes("API rate limit exceeded")) {
            console.warn(`[AI Image Search] Rate limit error received. Propagating to stop the background process.`);
            throw error;
        }
        console.error(`❌ [AI Image Search] Error during analysis for "${query}":`, error);
        return undefined;
    }
}

export async function getBestImageUsingAI(wordObject, deckObject) {
    console.log(`🧠 [AI Word Analysis] Starting for "${wordObject.text}".`);

    // We can call populateWordData locally here since we are in agent.js
    const populatedWord = await populateWordData(wordObject, deckObject);
    const definition = populatedWord.definitions.flashcard || 'No definition available.';

    if (definition.includes('not found') || definition.includes('Could not')) {
         console.log(`❌ [AI Word Analysis] No definition for "${wordObject.text}", cannot analyze images.`);
         return null;
    }

    const searchTermPrompt = `You are an AI that generates effective search terms for image APIs like Unsplash. Your goal is to find a visually descriptive image. Based on the following word and its definition, provide a single, concise search term (2-4 words is ideal). Respond with ONLY the search term itself, no quotes or extra text.\n\nWord: "${populatedWord.text}"\nDefinition: "${definition}"`;

    const searchTerm = await api.getGroqCompletion([{ role: 'user', content: searchTermPrompt }]);
    if (!searchTerm || searchTerm.trim() === '') {
        console.log(`❌ [AI Word Analysis] AI failed to generate a search term for "${wordObject.text}".`);
        return null;
    }
    const cleanSearchTerm = searchTerm.trim();
    console.log(`   [AI Word Analysis] Generated smart query: "${cleanSearchTerm}"`);

    const chosenImageUrl = await getBestImageForQuery(cleanSearchTerm, definition);

    if (chosenImageUrl) {
        return { imageUrl: chosenImageUrl, query: cleanSearchTerm }; 
    }
    return null;
}

export async function handleRefetchWordImage(wordObject, deckObject) {
    const toastId = 'ai-image-refetch';
    try {
        actions.showConfirmation({ title: "Refetching", message: "AI is generating a new search query...", isAlert: true }); // Using alert as toast replacement if toast not directly accessible or use passed action
        // Actually actions has ui.showToast
        actions.ui.showToast("AI is generating a new search query...", false, toastId, true);

        const populatedWord = await populateWordData(wordObject, deckObject);
        const context = populatedWord.definitions.flashcard || `The word is "${populatedWord.text}".`;
        const previousQuery = populatedWord.image_query || 'none';

        const searchTermPrompt = `You are an AI that generates effective search terms for image APIs like Unsplash. Your goal is to find a NEW and DIFFERENT image. The previous search query was "${previousQuery}". Based on the following word and its definition, provide a single, concise, and visually descriptive search term (2-4 words is ideal) that is different from the previous one. Respond with ONLY the search term itself, no quotes or extra text.\n\nWord: "${populatedWord.text}"\nDefinition: "${context}"`;

        const searchTerm = await api.getGroqCompletion([{ role: 'user', content: searchTermPrompt }]);
        if (!searchTerm) throw new Error("AI did not provide a search term.");

        actions.ui.showToast(`AI is searching for "${searchTerm}"...`, false, toastId, true);

        const chosenImageUrl = await getBestImageForQuery(searchTerm, context);

        if (chosenImageUrl) {
            populatedWord.imageUrl = chosenImageUrl;
            populatedWord.image_query = searchTerm; 
            populatedWord.isImageProvisional = false; 
            actions.saveDecks();

            // Refresh UI via action callback
            actions.openDeck(deckObject, populatedWord.text);

            actions.ui.hideToast(toastId);
            actions.ui.showToast("New image assigned successfully!");
        } else {
            throw new Error("AI couldn't find a suitable image for that search term.");
        }
    } catch (error) {
        actions.ui.hideToast(toastId);
        actions.ui.showToast(error.message, true);
        console.error("Error refetching image with AI:", error);
    }
}

export function selectPrioritizedWordsForQuiz(deck, count = 10) {
    if (!deck || !deck.words || deck.words.length === 0) return [];

    let words = [];
    let tempDeck = { ...deck }; // shallow copy

    for (let i = 0; i < count; i++) {
        const nextWord = selectNextWord(tempDeck);
        if (nextWord) {
            words.push(nextWord.text);
            // Exclude this word from the next selection
            tempDeck.words = tempDeck.words.filter(w => w.text !== nextWord.text);
        } else {
            break; // No more words to select
        }
    }
    return words;
}

export function calculateDeckStudyScore(deck) {
    if (!deck || !deck.words || !deck.words.length) return 0;
    const totalInterval = deck.words.reduce((sum, word) => sum + (word.interval || 0), 0);
    // Rough approximation: average interval of 30 days is "good progress"
    const targetAverage = 30;
    const percentage = (totalInterval / (deck.words.length * targetAverage)) * 100;
    return Math.min(100, Math.round(percentage));
}

