export function handleSaveFolder() {
    const { folders } = getState();
    const name = DOM.folderNameInput.value.trim();
    if (!name) { actions.ui.showToast("Please enter a folder name.", true); return; }

    const isDuplicate = folders.some(f => f.name.toLowerCase() === name.toLowerCase() && f.parentId === currentParentFolderId && f.id !== currentEditFolderId);
    if (isDuplicate) { actions.ui.showToast(`A folder named "${name}" already exists.`, true); return; }

    const selectedSwatch = DOM.folderColorPicker.querySelector('.color-swatch.selected');
    const color = selectedSwatch ? selectedSwatch.dataset.color : FOLDER_COLORS[0];

    if (currentEditFolderId) {
        const folder = folders.find(f => f.id === currentEditFolderId);
        if (folder) { folder.name = name; folder.color = color; }
    } else {
        folders.push({ id: `f_${Date.now()}`, name: name, color: color, parentId: currentParentFolderId });
    }

    actions.onSaveDecks(); 
    if (actions.onSaveFolders) actions.onSaveFolders();

    renderDeckScreen();
    actions.ui.closeAllModals();
    if (document.getElementById('manage-folders-screen').classList.contains('active')) {
