operations.content:
export function selectPrioritizedWordsForQuiz(deck, count = 10) {
    if (!deck || !deck.words || deck.words.length === 0) return [];

    let words = [];
    let tempDeck = { ...deck }; // shallow copy

    for (let i = 0; i < count; i++) {
        const nextWord = selectNextWord(tempDeck);
        if (nextWord) {
            words.push(nextWord.text);
            // Exclude this word from the next selection
            tempDeck.words = tempDeck.words.filter(w => w.text !== nextWord.text);
        } else {
            break; // No more words to select
        }
    }
    return words;
}

export function calculateDeckStudyScore(deck) {
    if (!deck || !deck.words || !deck.words.length) return 0;
    const totalInterval = deck.words.reduce((sum, word) => sum + (word.interval || 0), 0);
    // Rough approximation: average interval of 30 days is "good progress"
    const targetAverage = 30;
    const percentage = (totalInterval / (deck.words.length * targetAverage)) * 100;
    return Math.min(100, Math.round(percentage));
}

// --- Folder Management State ---
let currentEditFolderId = null;
let currentParentFolderId = null;
const FOLDER_COLORS = ['#3b82f6', '#ef4444', '#22c55e', '#f97316', '#8b5cf6', '#e879f9'];
let currentMoveTargetFolderId = null;

// --- Folder Logic ---

export function openAddEditFolderModal(folderToEdit = null, parentId = null) {
    currentEditFolderId = folderToEdit ? folderToEdit.id : null;
    currentParentFolderId = folderToEdit ? folderToEdit.parentId : parentId;

    if (folderToEdit) {
        DOM.folderModalTitle.textContent = "Edit Folder";
        DOM.folderNameInput.value = folderToEdit.name;
        DOM.saveFolderBtn.textContent = "Save Changes";
    } else {
        DOM.folderModalTitle.textContent = "New Folder";
        DOM.folderNameInput.value = "";
        DOM.saveFolderBtn.textContent = "Create Folder";
    }

    DOM.folderColorPicker.innerHTML = FOLDER_COLORS.map(color => `
        <div class="color-swatch" data-color="${color}" style="background-color: ${color};">
            <i class="ph-fill ph-check"></i>
        </div>
    `).join('');

    const selectedColor = folderToEdit ? folderToEdit.color : FOLDER_COLORS[0];
    const activeSwatch = DOM.folderColorPicker.querySelector(`[data-color="${selectedColor}"]`);
    if (activeSwatch) activeSwatch.classList.add('selected');

    actions.ui.showModal(DOM.addEditFolderModal);
}

export function handleSaveFolder() {
    const { folders } = getState();
    const name = DOM.folderNameInput.value.trim();
    if (!name) { actions.ui.showToast("Please enter a folder name.", true); return; }

    const isDuplicate = folders.some(f => f.name.toLowerCase() === name.toLowerCase() && f.parentId === currentParentFolderId && f.id !== currentEditFolderId);
    if (isDuplicate) { actions.ui.showToast(`A folder named "${name}" already exists.`, true); return; }

    const selectedSwatch = DOM.folderColorPicker.querySelector('.color-swatch.selected');
    const color = selectedSwatch ? selectedSwatch.dataset.color : FOLDER_COLORS[0];

    if (currentEditFolderId) {
        const folder = folders.find(f => f.id === currentEditFolderId);
        if (folder) { folder.name = name; folder.color = color; }
    } else {
        folders.push({ id: `f_${Date.now()}`, name: name, color: color, parentId: currentParentFolderId });
    }

    actions.onSaveDecks(); 
    if (actions.onSaveFolders) actions.onSaveFolders();

    renderDeckScreen();
    actions.ui.closeAllModals();
    if (document.getElementById('manage-folders-screen').classList.contains('active')) {
        renderManageFoldersList();
    }
}

export function renderManageFoldersList() {
    const { folders } = getState();
    const container = document.getElementById('manage-folders-list');
    if (!container) return;
    container.innerHTML = '';

    const buildHierarchy = (parentId, level) => {
        const children = folders.filter(f => f.parentId === parentId);
        children.forEach(folder => {
            const indent = level * 20;
            container.innerHTML += `
                <div class="manage-folder-item" data-folder-id="${folder.id}" style="margin-left: ${indent}px;">
                    <i class="ph-fill ph-folder" style="color: ${folder.color}; font-size: 1.5rem;"></i>
                    <div class="manage-folder-details">
                        <p class="manage-folder-name">${folder.name}</p>
                    </div>
                    <button class="folder-action-btn edit"><i class="ph ph-pencil-simple"></i></button>
                    <button class="folder-action-btn delete"><i class="ph ph-trash"></i></button>
                </div>`;
            buildHierarchy(folder.id, level + 1);
        });
    };
    buildHierarchy(null, 0);
}

// --- Move to Folder Logic ---

export function renderMoveToFolderList(parentId = null) {
    const { folders } = getState();
    const listEl = document.getElementById('move-to-folder-list');
    const headerTitleEl = document.getElementById('move-to-folder-header-title');
    const backBtn = document.getElementById('move-to-folder-back-btn');
    listEl.innerHTML = '';

    const getPath = (fid) => {
        if (!fid) return "Move to...";
        let path = [];
        let curr = folders.find(f => f.id === fid);
        while (curr) { path.unshift(curr.name); curr = folders.find(f => f.id === curr.parentId); }
        return `Move to... / ${path.join(' / ')}`;
    };

    headerTitleEl.textContent = getPath(parentId);
    if (parentId) {
        const parent = folders.find(f => f.id === parentId);
        backBtn.dataset.parentId = parent?.parentId || 'null';
        backBtn.style.visibility = 'visible';
    } else { backBtn.style.visibility = 'hidden'; }

    if (parentId === null) {
        listEl.innerHTML += `<div class="list-option" data-folder-id="null"><div class="list-option-main"><div class="list-option-icon-wrapper"><i class="ph ph-files"></i></div><p class="list-option-text">Top Level</p></div></div>`;
    }

    folders.filter(f => f.parentId === parentId).forEach(folder => {
        const hasChildren = folders.some(f => f.parentId === folder.id);
        const selected = currentMoveTargetFolderId === folder.id ? 'selected' : '';
        listEl.innerHTML += `<div class="list-option ${selected}" data-folder-id="${folder.id}"><div class="list-option-main"><div class="list-option-icon-wrapper"><i class="ph-fill ph-folder" style="color: ${folder.color};"></i></div><p class="list-option-text">${folder.name}</p></div>${hasChildren ? `<button class="drill-down-btn" data-folder-id="${folder.id}"><i class="ph ph-caret-right"></i></button>` : ''}</div>`;
    });
}

export function openMoveToFolderModal() {
    currentMoveTargetFolderId = null;
    renderMoveToFolderList(null);
    actions.ui.showModal(DOM.moveToFolderModal);
}

export function setCurrentMoveTargetFolderId(id) {
    currentMoveTargetFolderId = id;
}

export function getCurrentMoveTargetFolderId() {
    return currentMoveTargetFolderId;
}

export function handleMoveSelectedDecks(targetFolderId, selectedDeckIds) {
    const folderId = targetFolderId === 'null' ? null : targetFolderId;
    const { decks } = getState();
    selectedDeckIds.forEach(id => { const d = decks.find(d => d.id === id); if(d) d.folderId = folderId; });
    actions.onSaveDecks();
    renderDeckScreen();
    actions.ui.closeAllModals();
    actions.ui.showToast("Decks moved.");
}

