/**
 * Calculates a score for a deck representing its study progress.
 */
export function calculateDeckStudyScore(deck) {
    if (!deck || !deck.words || !deck.words.length) return 0;
    const totalInterval = deck.words.reduce((sum, word) => sum + (word.interval || 0), 0);
    const targetAverage = 30;
    const percentage = (totalInterval / (deck.words.length * targetAverage)) * 100;
    return Math.min(100, Math.round(percentage));
}

/**
 * Orchestrates the logging of global proficiency data.
 */
export function handleLogProficiency(proficiencyLog, decks, quizHistory, saveCallback, force = false) {
    if (!force) {
        const lastLog = proficiencyLog[proficiencyLog.length - 1];
        const TWENTY_FOUR_HOURS_MS = 24 * 60 * 60 * 1000;
        if (lastLog && (Date.now() - lastLog.timestamp < TWENTY_FOUR_HOURS_MS)) {
            return proficiencyLog;
        }
    }

    const currentStats = calculateGlobalProficiency(decks, quizHistory);
    proficiencyLog.push({ 
        timestamp: Date.now(), 
        score: currentStats.score 
    });
    saveCallback();
    return proficiencyLog;
}

/**
 * Selects a prioritized list of words from a deck for quiz generation.
 */
export function selectPrioritizedWordsForQuiz(deck, count = 10) {
    if (!deck || !deck.words || deck.words.length === 0) return [];

    let words = [];
    let tempDeck = { ...deck };
    const { selectNextWord } = actions;

    for (let i = 0; i < count; i++) {
        const nextWord = selectNextWord(tempDeck);
        if (nextWord) {
            words.push(nextWord.text);
            tempDeck.words = tempDeck.words.filter(w => w.text !== nextWord.text);
        } else {
            break;
        }
    }
    return words;
}

