    const { folders } = getState();
    const name = DOM.folderNameInput.value.trim();
    if (!name) { actions.ui.showToast("Please enter a folder name.", true); return; }

    const isDuplicate = folders.some(f => f.name.toLowerCase() === name.toLowerCase() && f.parentId === currentParentFolderId && f.id !== currentEditFolderId);
