async function explainJobFailure(id, name, e) {
    if(e) e.stopPropagation();
    const toast = document.getElementById('toast-msg') || document.createElement('div');
    toast.innerText = "🧠 Analyzing Log... Please wait.";
    toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#d946ef; color:white; padding:10px 20px; border-radius:30px; z-index:9999; box-shadow:0 5px 20px rgba(0,0,0,0.5);";
    document.body.appendChild(toast);

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'analyze_log', job_id: id })
        });
        const data = await res.json();
        toast.remove();

        if(data.analysis) {
            const modal = document.getElementById('op-modal');
            document.getElementById('op-modal-title').innerText = `Failure Analysis: ${name}`;

            const html = `
                <div style="padding:15px; color:#ddd; font-size:13px; line-height:1.6; display:flex; flex-direction:column; height:100%;">
                    <div style="background:#222; padding:15px; border-radius:8px; margin-bottom:15px; white-space:pre-wrap; font-family:'JetBrains Mono', monospace; font-size:12px; overflow-y:auto; flex:1; border:1px solid #333;">${data.analysis}</div>
                    <button class="btn btn-primary" onclick="navigator.clipboard.writeText(this.previousElementSibling.innerText).then(()=>alert('📋 Report Copied to Clipboard!'))">📋 Copy Report</button>
                </div>
            `;
            document.getElementById('op-modal-body').innerHTML = html;
            document.getElementById('op-modal-body').style.height = "60vh"; // Enforce height for scrolling
            modal.style.display = 'flex';
        }
    } catch(err) {
        toast.style.background = "var(--danger)";
        toast.innerText = "Error: " + err.message;
        setTimeout(() => toast.remove(), 3000);
    }
}

