// --- Module-level State ---
let newDeckData = { title: '', description: '', words: [], type: 'Vocabulary', manualWordsText: '', stagedImportWords: [] };

// --- Storage Keys ---
const STORAGE_KEYS = {
    DECKS: 'wordwiseDecks',
    FOLDERS: 'wordwiseFolders',
    SRS_MIGRATED: 'wordwiseSrsMigrated'
};

export function loadFolders() {
    const foldersJSON = localStorage.getItem(STORAGE_KEYS.FOLDERS);
    let folders = foldersJSON ? JSON.parse(foldersJSON) : [];
    let needsSave = false;

    // Migration: Add parentId to existing folders
    folders.forEach(folder => {
        if (!folder.hasOwnProperty('parentId')) {
            folder.parentId = null;
            needsSave = true;
        }
    });

    if (folders.length === 0) {
        console.log("No folders found. Creating a default folder.");
        folders = [{ id: 'f1', name: 'English', color: '#3b82f6', parentId: null }];
        needsSave = true;
    }

    if (needsSave) localStorage.setItem(STORAGE_KEYS.FOLDERS, JSON.stringify(folders));
    return folders;
}

export function saveFolders(folders) {
    localStorage.setItem(STORAGE_KEYS.FOLDERS, JSON.stringify(folders));
}

export function loadDecks() {
    const decksJSON = localStorage.getItem(STORAGE_KEYS.DECKS);
    let loadedDecks = decksJSON ? JSON.parse(decksJSON) : [];
    let needsSave = false;

    // WotD Deck Check
    const WOTD_DECK_ID = 'word_of_the_day_deck';
    const defaultWotdImage = 'https://images.unsplash.com/photo-1457369804613-52c61a468e7d?q=80&w=2070&auto=format&fit=crop';
    let wotdDeck = loadedDecks.find(d => d.id === WOTD_DECK_ID);

    if (!wotdDeck) {
        wotdDeck = {
            id: WOTD_DECK_ID,
            title: "Word of the Day",
            description: "A collection of daily words from Merriam Webster.",
            words: [],
            type: 'Vocabulary',
            isSpecial: true,
            imageUrl: defaultWotdImage,
            createdAt: new Date().toISOString()
        };
        loadedDecks.unshift(wotdDeck);
        needsSave = true;
    } else if (!wotdDeck.imageUrl) {
        wotdDeck.imageUrl = defaultWotdImage;
        needsSave = true;
    }

    // Migration Logic
    loadedDecks.forEach(deck => {
        if (!deck.hasOwnProperty('folderId')) {
            deck.folderId = null;
            needsSave = true;
        }
        if (deck.words && deck.words.length > 0) {
            let deckWasMigrated = false;
            deck.words = deck.words.map(word => {
                if (typeof word === 'string' || !word.hasOwnProperty('definitions')) {
                    deckWasMigrated = true;
                    return {
                        text: typeof word === 'string' ? word : word.text,
                        masteryLevel: word.masteryLevel || 0,
                        lastSeen: word.lastSeen || null,
                        imageUrl: null,
                        isImageProvisional: true,
                        definitions: { flashcard: null, detailed: null, gemini: null, mwDictionary: null, mwThesaurus: null }
                    };
                }
                if (!word.definitions.mwDictionary) { word.definitions.mwDictionary = null; deckWasMigrated = true; }
                if (!word.definitions.mwThesaurus) { word.definitions.mwThesaurus = null; deckWasMigrated = true; }
                return word;
            });
            if (deckWasMigrated) needsSave = true;
        }
    });

    // SRS Migration Check
    if (!localStorage.getItem(STORAGE_KEYS.SRS_MIGRATED)) {
        console.log("Migrating SRS data...");
        const oldIntervals = [1, 3, 7, 14, 30, 90, 180];
        loadedDecks.forEach(deck => {
            deck.words.forEach(word => {
                if (word.hasOwnProperty('masteryLevel')) {
                    needsSave = true;
                    const level = word.masteryLevel || 0;
                    word.interval = level > 0 ? oldIntervals[Math.min(level - 1, oldIntervals.length - 1)] : 0;
                    word.factor = 2.5;
                    delete word.masteryLevel;
                }
            });
        });
        localStorage.setItem(STORAGE_KEYS.SRS_MIGRATED, 'true');
    }

    if (needsSave) localStorage.setItem(STORAGE_KEYS.DECKS, JSON.stringify(loadedDecks));
    return loadedDecks;
}

export function saveDecks(decks) {
    localStorage.setItem(STORAGE_KEYS.DECKS, JSON.stringify(decks));
}

