export function handleGlobalClick(e, selectionModeState, toggleSelection) {
    const wotdLogBtn = e.target.closest('.wotd-log-btn');
    if (wotdLogBtn) {
        e.preventDefault(); e.stopPropagation(); actions.ui.closeActiveMenu();
        const { decks } = getState();
        const wotdDeck = decks.find(d => d.isSpecial);
        if (wotdDeck) {
            actions.ui.renderWotdLog(wotdDeck);
            actions.ui.showModal(document.getElementById('wotd-log-screen'));
        }
        return true;
    }

    const wotdLogEntry = e.target.closest('.wotd-log-entry');
    if (wotdLogEntry) {
        e.preventDefault();
        if (selectionModeState && selectionModeState.wotd) {
            toggleSelection('wotd', wotdLogEntry);
        } else {
            const wordText = wotdLogEntry.querySelector('.wotd-log-word').textContent;
            const { decks } = getState();
            const wotdDeck = decks.find(d => d.isSpecial);
            const wordObject = wotdDeck?.words.find(w => w.text === wordText);
            if (wordObject) openWotdPortfolio(wordObject);
        }
        return true;
    }
    return false;
}

