export function handleGlobalClick(e) {
    // --- Navigation & Search ---
    if (e.target.closest('#show-movie-search-btn')) {
        e.stopPropagation();
        document.getElementById('movie-list-header').classList.add('search-active');
        document.getElementById('movie-list-search-input').focus();
        return true;
    }

    // --- Add Movie Flow ---
    if (e.target.closest('#add-movie-btn')) {
        foundMovieData = null;
        DOM.movieSearchInput.value = '';
        DOM.movieSearchStatus.textContent = '';
        const manualToggleP = document.getElementById('show-manual-entry-btn')?.closest('p');
        if (manualToggleP) manualToggleP.style.display = 'block';
        DOM.apiSearchResult.style.display = 'none';
        DOM.manualEntryForm.style.display = 'none';
        document.getElementById('manual-movie-title').value = '';
        document.getElementById('manual-movie-description').value = '';
        const posterPreview = document.getElementById('manual-poster-preview');
        posterPreview.src = '';
        posterPreview.style.display = 'none';

        actions.showModal(DOM.screens.addMovie);

        if (!navigator.onLine) {
            DOM.movieSearchInput.disabled = true;
            DOM.movieSearchBtn.disabled = true;
            DOM.movieSearchStatus.textContent = 'Movie search is unavailable offline.';
            DOM.manualEntryForm.style.display = 'block';
        }
        return true;
    }

    if (e.target.closest('#movie-search-btn')) { handleOMDbSearch(); return true; }
    if (e.target.closest('#show-manual-entry-btn')) {
        e.preventDefault();
        DOM.manualEntryForm.style.display = 'block';
        e.target.closest('p').style.display = 'none';
        return true;
    }
    if (e.target.closest('#add-movie-submit-btn')) { handleAddMovieSubmit(); return true; }
    if (e.target.closest('#manual-assign-poster-btn')) {
        const title = document.getElementById('manual-movie-title').value.trim();
        if (!title) {
            actions.showToast("Please enter a movie title before searching for a poster.", true);
            return true;
        }
        actions.openImageSearch({
            type: 'movie_poster',
            id: null,
            defaultQuery: title,
            searchProvider: 'google'
        });
        return true;
    }

    // --- Movie Card & Play ---
    const movieCard = e.target.closest('.movie-card');
    if (movieCard && !e.target.closest('.options-container')) {
        showMovieDetail(movieCard.dataset.id);
        return true;
    }
    if (e.target.closest('#play-movie-btn')) {
        if (currentMovieId) playMovie(currentMovieId);
        return true;
    }

    // --- Player Controls & Subtitles ---
    if (e.target.closest('#switch-to-text-mode-btn')) {
        e.preventDefault();
        actions.closeActiveMenu();
        const videoPlayer = document.getElementById('main-video-player');
        if (videoPlayer && !videoPlayer.paused) videoPlayer.pause();
        cameFromVideoPlayer = true;
        playTextReader(currentlyPlayingItemId);
        return true;
    }
    if (e.target.closest('#customize-subs-btn')) {
        e.preventDefault();
        document.getElementById('subtitle-customization-modal').classList.add('active');
        actions.closeActiveMenu();
        return true;
    }
    if (e.target.closest('#back-to-video-player-btn')) {
        actions.showModal(DOM.screens.videoPlayer);
        const videoPlayer = document.getElementById('main-video-player');
        if (videoPlayer && videoPlayer.paused) videoPlayer.play();
        return true;
    }

    // --- Subtitle Addition ---
    const subtitleAddBtn = e.target.closest('.subtitle-add-btn');
    if (subtitleAddBtn && !subtitleAddBtn.disabled) {
        addSubtitleToDeck(subtitleAddBtn.dataset.text, subtitleAddBtn.dataset.timestamp, subtitleAddBtn);
        return true;
    }

    // --- Create Deck from Movie ---
    if (e.target.closest('.create-deck-from-movie-btn')) {
        e.preventDefault(); e.stopPropagation(); actions.closeActiveMenu();
        // ... (Existing logic for creating deck from movie)
        // Note: For brevity in this refactor step, I'm delegating the full logic call back to app.js's handleMovieEvents
        // But ideally, the logic inside handleMovieEvents for this button should move here.
        // Since we are replacing the listener in app.js, we must return false so app.js calls handleMovieEvents
        // OR we simply move handleMovieEvents entirely. 
        // Strategy: We will call handleMovieEvents from app.js as a fallback, but handle specific UI triggers here.
        // Actually, handleMovieEvents in movie.js ALREADY handles clicks. 
        // We just need to expose it properly or use it directly.
        return false; // Let handleMovieEvents handle complex logic
    }

    return false;
}

