    if (!force) {
        const lastLog = proficiencyLog[proficiencyLog.length - 1];
        const TWENTY_FOUR_HOURS_MS = 24 * 60 * 60 * 1000;
        if (lastLog && (Date.now() - lastLog.timestamp < TWENTY_FOUR_HOURS_MS)) {
